INSERT INTO "NewsArticle" VALUES ('cmnuwohyu006vwrhpfcb69ksl', 'Robert Plant honoured as Record Store Legend ahead of RSD 2026: “Record stores have always been a part of my life”', 'robert-plant-honoured-as-record-store-legend-ahead-of-rsd-2026-record-stores-have-always-been-a-part', 'Ahead of Record Store Day 2026, Robert Plant has been named as this year’s Record Store Legend. The 19th instalment of RSD is taking place next week (April 18), a celebration of independent record shops and vinyl culture in the UK involving more than 300 stores around the country. An extensive range of exclusive physical releases will be available on a first-come-first-served basis, with records from the likes of Charli XCX, Muse, Suede, David Bowie, The Cure, KPop Demon Hunters,...', 'https://www.nme.com/news/music/robert-plant-honoured-as-record-store-legend-ahead-of-rsd-2026-record-stores-have-always-been-a-part-of-my-life-3939715?utm_source=rss&utm_medium=rss&utm_campaign=robert-plant-honoured-as-record-store-legend-ahead-of-rsd-2026-record-stores-have-always-been-a-part-of-my-life', 'https://www.nme.com/wp-content/uploads/2026/04/robert_plant_live.jpg', true, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-11 19:51:57', '2026-04-11 22:27:59.862', '2026-04-12 12:53:07.175', false, 'via NME', NULL);
