INSERT INTO "NewsArticle" VALUES ('cmnuwohzc006zwrhpxyv2uw1o', 'Dolly Parton is the most popular person in America, poll finds', 'dolly-parton-is-the-most-popular-person-in-america-poll-finds', 'An academic poll has found that Dolly Parton is the most popular public figure in the US today. READ MORE: The Big Read – Dolly Parton: “I take care of business” According to a national survey of American adults conducted by the University of Massachusetts Lowell, the country music icon fared more favorably than any of the other suggested figures, including all of the country’s major political players. Parton sits on an impressive +65 rating, comfortably ahead of Taylor Swift,...', 'https://www.nme.com/news/music/dolly-parton-is-the-most-popular-person-in-america-poll-finds-3939697?utm_source=rss&utm_medium=rss&utm_campaign=dolly-parton-is-the-most-popular-person-in-america-poll-finds', 'https://www.nme.com/wp-content/uploads/2026/04/dolly_parton_2026.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-11 16:24:06', '2026-04-11 22:27:59.88', '2026-04-11 22:27:59.88', false, 'via NME', NULL);
