INSERT INTO "NewsArticle" VALUES ('cmnp43rwm001007hpwba4eauu', 'Jewish groups respond to Kanye West’s offer to meet – but say he still shouldn’t play Wireless', 'jewish-groups-respond-to-kanye-west-s-offer-to-meet-but-say-he-still-shouldn-t-play-wireless', 'Multiple Jewish groups have responded to Kanye West’s offer to meet and discuss his history of anti-Semitic comments, and said that he should not play at Wireless Festival. The rapper has a history of making anti-Semitic remarks on social media and in interviews. Recently, he was announced last week as the headliner for all three nights of the festival in London’s Finsbury Park in July, with the shows being described as a three-night journey through his “most iconic records”. Unsurprisingly,...', 'https://www.nme.com/news/music/jewish-groups-respond-to-kanye-wests-offer-to-meet-but-say-he-still-shouldnt-play-wireless-3938858?utm_source=rss&utm_medium=rss&utm_campaign=jewish-groups-respond-to-kanye-wests-offer-to-meet-but-say-he-still-shouldnt-play-wireless', 'https://www.nme.com/wp-content/uploads/2026/04/kanye@2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-07 10:32:01', '2026-04-07 21:09:12.838', '2026-04-07 21:09:12.838', false, NULL, NULL);
