INSERT INTO "NewsArticle" VALUES ('cmnktxo4i00afsohplo6fbzal', 'Judge blocks Donald Trump’s attempt to end federal funding for NPR and PBS', 'judge-blocks-donald-trump-s-attempt-to-end-federal-funding-for-npr-and-pbs', 'A judge has blocked an executive order from Donald Trump that sought to end federal funding of “biased media” outlets NPR and PBS. Last May, the president signed the order, which directed the Corporation for Public Broadcasting (CPB) – the body that sends funds to the two radio platforms – to “cease federal funding” to them. The order stated that “Americans have the right to expect that if their tax dollars fund public broadcasting at all, they fund only fair,...', 'https://www.nme.com/news/music/judge-blocks-donald-trumps-attempt-to-end-federal-funding-for-npr-and-pbs-3938481?utm_source=rss&utm_medium=rss&utm_campaign=judge-blocks-donald-trumps-attempt-to-end-federal-funding-for-npr-and-pbs', 'https://www.nme.com/wp-content/uploads/2026/04/donald_Trump_new.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-04 19:50:35', '2026-04-04 21:13:27.138', '2026-04-04 21:13:27.138', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmnktxo4n00agsohpfj8cjca0', 'Fan project to preserve and document career of SOPHIE', 'fan-project-to-preserve-and-document-career-of-sophie', 'A new project organised by fans will aim to fully document the career of the late and highly influential producer and musician SOPHIE. READ MORE: SOPHIE, 1986-2021: the “icon of liberation” who changed pop forever The pioneering Scottish artist, who consistently pushed the boundaries of electronic experimentation, passed away in January 2021 in a tragic accident in Athens. She has been cited as a key influence by the likes of Charli XCX, Vince Staples, FKA twigs, Jack Antonoff and Sam...', 'https://www.nme.com/news/music/fan-project-to-preserve-and-document-career-of-sophie-3938467?utm_source=rss&utm_medium=rss&utm_campaign=fan-project-to-preserve-and-document-career-of-sophie', 'https://www.nme.com/wp-content/uploads/2026/04/sophie_coachella_2019.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-04 19:02:11', '2026-04-04 21:13:27.143', '2026-04-04 21:13:27.143', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmnktxo4s00ahsohpe9x0o0bg', 'Christina Hendricks played an indie-packed “shoe pop dream gaze” DJ set at a San Diego bar on April Fool’s Day', 'christina-hendricks-played-an-indie-packed-shoe-pop-dream-gaze-dj-set-at-a-san-diego-bar-on-april-fo', 'Christina Hendricks played a four-hour DJ set of indie, shoegaze and dream pop classics in San Diego this week – see footage and the setlist below. READ MORE: Soundtrack Of My Life: Christina Hendricks The Mad Men star announced that she would be behind the decks for a stint at the city’s Part Time Lover bar on Wednesday (April 1), and actually showed up to play what has been dubbed a “shoe pop dream gaze” set entirely on vinyl. As...', 'https://www.nme.com/news/music/christina-hendricks-played-an-indie-packed-shoe-pop-dream-gaze-dj-set-at-a-san-diego-bar-on-april-fools-day-3938464?utm_source=rss&utm_medium=rss&utm_campaign=christina-hendricks-played-an-indie-packed-shoe-pop-dream-gaze-dj-set-at-a-san-diego-bar-on-april-fools-day', 'https://www.nme.com/wp-content/uploads/2026/04/christina_hendricks_2025.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-04 17:43:25', '2026-04-04 21:13:27.148', '2026-04-04 21:13:27.148', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmnktxo4z00aisohpa8nsd52g', 'Ringo Starr’s secret to anti-ageing: “Peace and love and broccoli”', 'ringo-starr-s-secret-to-anti-ageing-peace-and-love-and-broccoli', 'Ringo Starr has revealed his unique culinary tip for slowing the ageing experience. READ MORE: The Beatles: every song ranked in order of greatness The Beatles drummer is preparing to release his 22nd solo album ‘Long Long Road’, which sees him joined by St. Vincent, Sheryl Crow and Billy Strings, on April 24 via UMe (pre-order your copy here). In a new interview with Rolling Stone, Starr, who will turn 86 in July, has opened up about how he keeps...', 'https://www.nme.com/news/music/ringo-starrs-secret-to-anti-ageing-peace-and-love-and-broccoli-3938455?utm_source=rss&utm_medium=rss&utm_campaign=ringo-starrs-secret-to-anti-ageing-peace-and-love-and-broccoli', 'https://www.nme.com/wp-content/uploads/2026/04/ringo_starr_2025.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-04 16:05:35', '2026-04-04 21:13:27.155', '2026-04-04 21:13:27.155', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmnktxo5300ajsohpv188wffx', 'Beck leads tributes to legendary soul drummer James Gadson: “You taught us more than you’ll ever know”', 'beck-leads-tributes-to-legendary-soul-drummer-james-gadson-you-taught-us-more-than-you-ll-ever-know', 'James Gadson, a drummer who played on a host of classic funk, soul and disco recordings, has died at the age of 86. Gadson’s wife Barbara confirmed the news to Rolling Stone on Friday (April 3), who revealed that he had recently undergone surgery after a number of health challenges, including a bad fall that injured his back. “He was a wonderful man,” Barbara said. “He was a great husband, father, grandfather, great grandfather, and one hell of a drummer.”...', 'https://www.nme.com/news/music/james-gadson-drummer-for-diana-ross-marvin-gaye-and-bill-withers-dies-aged-86-3938346?utm_source=rss&utm_medium=rss&utm_campaign=james-gadson-drummer-for-diana-ross-marvin-gaye-and-bill-withers-dies-aged-86', 'https://www.nme.com/wp-content/uploads/2026/04/james_gadson_rip.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-04 15:20:51', '2026-04-04 21:13:27.159', '2026-04-04 21:13:27.159', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmnktxo5700aksohpxjkm2pan', 'The xx play first of three sold-out Mexico City comeback gigs – their first in eight years', 'the-xx-play-first-of-three-sold-out-mexico-city-comeback-gigs-their-first-in-eight-years', 'The xx played their first gig in eight years last night (April 3) – check out footage, photos and the full setlist from the landmark show below. READ MORE: Romy on being back in the studio with The xx: “We’re up for trying new things but it sounds like us” Earlier this year, the trio announced that their first show together since 2018 would be held at the Pepsi Center WTC in the Mexican capital, with festival appearances at Coachella...', 'https://www.nme.com/news/music/the-xx-mexico-city-comeback-gigs-april-2026-photos-footage-setslist-3938406?utm_source=rss&utm_medium=rss&utm_campaign=the-xx-mexico-city-comeback-gigs-april-2026-photos-footage-setslist', 'https://www.nme.com/wp-content/uploads/2026/04/thexx_live_nine.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-04 10:52:30', '2026-04-04 21:13:27.163', '2026-04-04 21:13:27.163', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmnktxo5b00alsohps6zvxr32', '50 Cent asks God to “forgive” his enemies for “misunderstanding” him on Good Friday', '50-cent-asks-god-to-forgive-his-enemies-for-misunderstanding-him-on-good-friday', '50 Cent has shared a Good Friday prayer for his enemies. The rapper took to Instagram yesterday (April 3) to ask God to “forgive” those he’s disagreed with for “misunderstanding” him on the holy day. “Father God forgive me for my sins, forgive me for eating so much peanut butter and jelly, I’m big ass shit now,” he began. “Father God forgive my enemies for misunderstanding me, allow your light to shine so bright within me that my aura glows,...', 'https://www.nme.com/news/music/50-cent-asks-god-to-forgive-his-enemies-for-misunderstanding-him-on-good-friday-3938421?utm_source=rss&utm_medium=rss&utm_campaign=50-cent-asks-god-to-forgive-his-enemies-for-misunderstanding-him-on-good-friday', 'https://www.nme.com/wp-content/uploads/2026/04/50-Cent.-CREDIT_-Alexander-Tamargo_Getty-Images-for-Best-Buddies-International.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-04 10:29:31', '2026-04-04 21:13:27.167', '2026-04-04 21:13:27.167', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmnktxo5e00amsohpomv6i4ge', 'Mel B says Spice Girls reunion tour is “not happening”, addresses documentary rumours', 'mel-b-says-spice-girls-reunion-tour-is-not-happening-addresses-documentary-rumours', 'Mel B has put long swirling rumours of a Spice Girls reunion tour to rest in a new interview. READ MORE: Spice Girls’ ‘Wannabe’ at 25: what we’ve learned from the iconic girl group since The singer, also known as Scary Spice, nodded to the group’s upcoming 30th anniversary in a discussion with Hello!, and dashed hopes of a comeback tour. With the milestone imminent, fans have been clambering to see them come back together in some capacity, either for...', 'https://www.nme.com/news/music/mel-b-says-spice-girls-reunion-tour-is-not-happening-addresses-documentary-rumours-3938430?utm_source=rss&utm_medium=rss&utm_campaign=mel-b-says-spice-girls-reunion-tour-is-not-happening-addresses-documentary-rumours', 'https://www.nme.com/wp-content/uploads/2026/04/live-the-spice-girls.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-04 10:29:30', '2026-04-04 21:13:27.17', '2026-04-04 21:13:27.17', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmnktxo5i00ansohp96p89ntz', 'Watch Muse debut new songs ‘Cryogen’ and ‘Be With You’ at intimate, explosive Brixton Academy show', 'watch-muse-debut-new-songs-cryogen-and-be-with-you-at-intimate-explosive-brixton-academy-show', 'Muse kicked off their new era by debuting new songs from upcoming album ‘The Wow! Signal‘ and airing fan favourites at their return to London’s O2 Academy Brixton last night (Friday April 3). Check out photos, footage, the setlist and more below. Fans had been queuing from the day before to get to the front row for the Devonshire space rock trio’s first performance at the iconic venue since May 2001. An intimate show for the stadium band, demand was...', 'https://www.nme.com/news/music/muse-o2-academy-brixton-march-2026-gig-report-photos-footage-setlist-3938397?utm_source=rss&utm_medium=rss&utm_campaign=muse-o2-academy-brixton-march-2026-gig-report-photos-footage-setlist', 'https://www.nme.com/wp-content/uploads/2026/04/muse_brixton_MAIN.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-04 10:05:49', '2026-04-04 21:13:27.174', '2026-04-04 21:13:27.174', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmnktxo5l00aosohpnln02w2o', 'BTS unveil hidden ‘AIRIRANG’ track produced by Suga', 'bts-unveil-hidden-airirang-track-produced-by-suga', 'BTS have unveiled a surprise surprise hidden ‘ARIRANG‘ track. Find all the details below. READ MORE: BTS – ‘Arirang’ review: Korea’s pop kings make a grand return The K-Pop icons first hinted about the bonus track, which is only available on the project’s deluxe vinyl, on Wednesday (April 1), when, during a livestream on Weverse, Suga told fans: “A song that I produced is coming out soon – it’s finally coming out, a special song on the LP.” RM also...', 'https://www.nme.com/news/music/bts-unveil-hidden-airirang-track-produced-by-suga-3938389?utm_source=rss&utm_medium=rss&utm_campaign=bts-unveil-hidden-airirang-track-produced-by-suga', 'https://www.nme.com/wp-content/uploads/2026/03/arirang-bts-review-big-hit-music.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-04 09:36:30', '2026-04-04 21:13:27.177', '2026-04-04 21:13:27.177', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmnuwohzm0072wrhp2p6j3w24', 'Watch Ninajirachi and Porter Robinson debut new song at Coachella 2026', 'watch-ninajirachi-and-porter-robinson-debut-new-song-at-coachella-2026', 'Ninajirachi and Porter Robinson debuted a new collaboration at Coachella 2026 – check it out below. READ MORE: ‘I Love My Computer’ is the album of Ninajirachi’s electric dreams Robinson surprised the crowd during Ninajirachi’s debut set at the Californian festival last night (April 10). His appearance validated fan speculation after a teaser was posted to his website earlier in the week, which included a countdown to Ninajirachi’s Coachella set. During the performance, the pair gave festivalgoers an early listen...', 'https://www.nme.com/news/music/watch-ninajirachi-and-porter-robinson-debut-new-song-at-coachella-2026-3939656?utm_source=rss&utm_medium=rss&utm_campaign=watch-ninajirachi-and-porter-robinson-debut-new-song-at-coachella-2026', 'https://www.nme.com/wp-content/uploads/2026/04/Ninajirachi-and-Porter-Robinson.-CREDIT_-Santiago-Felipe_Getty-Images-and-Dia-Dipasupil_Getty-Images.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-11 10:29:02', '2026-04-11 22:27:59.89', '2026-04-11 22:27:59.89', false, 'via NME', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnuwohzp0073wrhpb6u3ooq9', 'Turnstile open Coachella set with recording of Brendan Yates’ father after band’s former guitarist was arrested for his attempted murder', 'turnstile-open-coachella-set-with-recording-of-brendan-yates-father-after-band-s-former-guitarist-wa', 'Turnstile kicked off their Coachella set by addressing news that their former guitarist Brady Ebert hit singer Brendan Yates’ father with his car. READ MORE: Turnstile – ‘Never Enough’ review: heartfelt hardcore poptimism Earlier this month, reports emerged that Ebert, who parted ways with Turnstile in 2022, had been arrested for attempted second-degree murder and first-degree assault, and it later transpired that Ebert was said to have run over vocalist Yates’ father, William, with his car. According to The Baltimore...', 'https://www.nme.com/news/music/turnstile-open-coachella-set-with-recording-of-brendan-yates-father-after-bands-former-guitarist-was-arrested-for-his-attempted-murder-3939624?utm_source=rss&utm_medium=rss&utm_campaign=turnstile-open-coachella-set-with-recording-of-brendan-yates-father-after-bands-former-guitarist-was-arrested-for-his-attempted-murder', 'https://www.nme.com/wp-content/uploads/2026/04/live-tunstile-coachella.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-11 09:48:46', '2026-04-11 22:27:59.893', '2026-04-11 22:27:59.893', false, 'via NME', NULL);
