INSERT INTO "NewsArticle" VALUES ('cmnvoxau9000fwvhpu8iy5186', 'Labrinth Says He Quit Euphoria Because He Doesn’t “Let People Treat Me Like Shit”', 'labrinth-says-he-quit-euphoria-because-he-doesn-t-let-people-treat-me-like-shit', 'Since the very beginning of Euphoria, Labrinth has provided the score. The controversial HBO drama returns tomorrow, and last month the British musician declared on social media, "Fuck Columbia. Double Fuck Euphoria. I''m out. Thank you and good night." Earlier this week the show''s creator Sam Levinson addressed the issue for the first time in an interview with Rolling Stone, and now Labrinth is sharing more of his side of things. The post Labrinth Says He Quit <em>Euphoria</em> Because He...', 'https://stereogum.com/2495509/labrinth-says-he-quit-euphoria-because-he-doesnt-let-people-treat-me-like-shit/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/labrinth.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-11 18:03:54', '2026-04-12 11:38:39.777', '2026-04-12 11:38:39.777', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxci3000iwvhpd7t3b9hn', 'David Lee Roth, Vanessa Carlton, & Joe Jonas Make Surprise Coachella Debuts With Teddy Swims', 'david-lee-roth-vanessa-carlton-joe-jonas-make-surprise-coachella-debuts-with-teddy-swims', 'Teddy Swims'' Coachella set abounded with special guests. The "Lose Control" singer used his main stage performance to bring out David Lee Roth, Vanessa Carlton, and Joe Jonas for their debut performances at the Indio music festival. The post David Lee Roth, Vanessa Carlton, & Joe Jonas Make Surprise Coachella Debuts With Teddy Swims appeared first on Stereogum.', 'https://stereogum.com/2495487/david-lee-roth-vanessa-carlton-joe-jonas-make-surprise-coachella-debuts-with-teddy-swims/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Screenshot-2026-04-11-at-10.58.14-AM.png', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-11 15:00:31', '2026-04-12 11:38:41.931', '2026-04-12 11:38:41.931', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxcqj000jwvhphzuh8nyf', 'Turnstile Open Coachella Set With Recording Of Brendan Yates’ Father', 'turnstile-open-coachella-set-with-recording-of-brendan-yates-father', 'Coachella kicked off yesterday, with Sabrina Carpenter headlining and Slayyyter drawing a big crowd for her much-hyped new album WOR$T GIRL IN AMERICA. The night also had Turnstile''s first performance since former guitarist Brady Ebert was charged with attempted murder of Brendan Yates'' father. The set began with a recording of Yates'' father. The post Turnstile Open Coachella Set With Recording Of Brendan Yates’ Father appeared first on Stereogum.', 'https://stereogum.com/2495483/turnstile-open-coachella-set-with-recording-of-brendan-yates-father/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/turnstile.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-11 13:56:38', '2026-04-12 11:38:42.235', '2026-04-12 11:38:42.235', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxd8g000kwvhp1e8e3koe', 'The Coachella 2026 Livestream Is Here', 'the-coachella-2026-livestream-is-here', 'Summer festival season is officially here. Coachella, the annual California desert bacchanal that traditionally kicks off the year''s endless procession of big-ticket fests, is taking place this weekend and next at Empire Polo Club in Indio. We posted and analyzed this year''s lineup way back in September, and now the fest''s 2026 edition is finally getting started. This year''s livestream begins today at 7 p.m. ET/4 p.m. PT. The post The Coachella 2026 Livestream Is Here appeared first on Stereogum.', 'https://stereogum.com/2495455/the-coachella-2026-livestream-is-here/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/coachella.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 21:23:04', '2026-04-12 11:38:42.88', '2026-04-12 11:38:42.88', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxds7000lwvhp20eb0qcg', 'Belle And Sebastian Debut New Scottish Football Anthem “It Only Takes One Lion”', 'belle-and-sebastian-debut-new-scottish-football-anthem-it-only-takes-one-lion', 'Despite having a song called "The Stars Of Track And Field," back in the day, Belle And Sebastian''s image was not especially athletic. The songs were for and about shy, bookish types, and frontman Stuart Murdoch''s struggle with chronic fatigue syndrome is what led to him writing songs in the first place. Yet the band has evolved, and Murdoch, who used to run marathons before his health declined, was back to his racing ways by the time they made the...', 'https://stereogum.com/2495466/belle-and-sebastian-debut-new-scottish-football-anthem-it-only-takes-one-lion/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Belle.png', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 20:35:35', '2026-04-12 11:38:43.591', '2026-04-12 11:38:43.591', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxe5w000mwvhpn0dlkc76', 'Gucci Mane Addresses Robbery & Kidnapping On Pooh Shiesty Diss Track “Crash Dummy”', 'gucci-mane-addresses-robbery-kidnapping-on-pooh-shiesty-diss-track-crash-dummy', 'A week ago, we got some startling news from the rap world: Memphis rap stars Pooh Shiesty and Big30 were among a group of men arrested on robbery and kidnapping charges for an incident at a Dallas recording studio involving Gucci Mane. Shiesty, who is signed to Gucci’s record label 1017, allegedly set up a… The post Gucci Mane Addresses Robbery & Kidnapping On Pooh Shiesty Diss Track “Crash Dummy” appeared first on Stereogum.', 'https://stereogum.com/2495462/gucci-mane-addresses-robbery-kidnapping-on-pooh-shiesty-diss-track-crash-dummy/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/SnapInsta-Ai_3871888752684111868.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 20:12:52', '2026-04-12 11:38:44.084', '2026-04-12 11:38:44.084', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvmcpkg0006wvhpcuf7duqt', 'Nine Inch Noize perform first-ever full set at Coachella 2026', 'nine-inch-noize-perform-first-ever-full-set-at-coachella-2026', 'Industrial giants Nine Inch Nails and German producer Boys Noize joined forces for their first full set as ‘Nine Inch Noize’ at Coachella 2026 – check out clips of their performance below. READ MORE: Coachella 2026: see set and stage times, livestream schedule and how to watch Expanding on the smaller sets both artists have played together on the past year’s ‘Peel It Back’ tour, their set last night (April 11) opened with a remix of Nails’ 2007 track ‘Vessel’,...', 'https://www.nme.com/news/music/nine-inch-noize-perform-first-ever-full-set-at-coachella-2026-3939751?utm_source=rss&utm_medium=rss&utm_campaign=nine-inch-noize-perform-first-ever-full-set-at-coachella-2026', 'https://www.nme.com/wp-content/uploads/2026/04/live-nine-ich-noize.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 08:52:48', '2026-04-12 10:26:39.856', '2026-04-12 10:26:39.856', false, 'via NME', NULL);
