INSERT INTO "NewsArticle" VALUES ('cmnvoxfim000owvhp3bsdwpd4', 'Kehlani – “Back And Forth” (Feat. Missy Elliott)', 'kehlani-back-and-forth-feat-missy-elliott', 'Kehlani is following up the massive success of “Folded” with a new self-titled album due later this month. The album has “Folded” and “Out The Window,” and today we get a third preview with a noteworthy special guest. None other than Missy “Misdemeanor” Elliott graces “Back And Forth,” Kehlani’s appealing new single out today. Miss… The post Kehlani – “Back And Forth” (Feat. Missy Elliott) appeared first on Stereogum.', 'https://stereogum.com/2495446/kehlani-back-and-forth-feat-missy-elliott/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-2026-04-10T132023.955-1.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 17:34:49', '2026-04-12 11:38:45.838', '2026-04-12 11:38:45.838', false, 'Stereogum', NULL);
