INSERT INTO "NewsArticle" VALUES ('cmns1gboe000awshpkwp3rxft', 'LIDO Festival cancels CMAT and Bombay Bicycle Club days, reschedules Maribou State', 'lido-festival-cancels-cmat-and-bombay-bicycle-club-days-reschedules-maribou-state', 'LIDO Festival has rescheduled its Maribou State headline show and cancelled the days topped by CMAT and Bombay Bicycle Club due to concerns about the grounds at Victoria Park. READ MORE: Charli XCX’s Partygirl live in London: celebrating the community and creators of ‘Brat’ summer The East London festival launched last year after being announced in late 2024. It is run by AEG Presents, who also organise All Points East, BST Hyde Park, Forwards and more. It was set to...', 'https://www.nme.com/news/music/lido-festival-cancels-cmat-bombay-bicycle-club-performances-reschedules-maribou-state-3939333?utm_source=rss&utm_medium=rss&utm_campaign=lido-festival-cancels-cmat-bombay-bicycle-club-performances-reschedules-maribou-state', 'https://www.nme.com/wp-content/uploads/2025/06/NMEAR_NME-GLASTO-2025_CMAT_Pyramid_AFord-620828.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-09 15:00:09', '2026-04-09 22:18:18.014', '2026-04-09 22:18:18.014', false, NULL, NULL);
