INSERT INTO "NewsArticle" VALUES ('cmns1gbom000cwshpo8te5wox', 'Doja Cat says she’s “tickled” by Madonna trolls: “You feel threatened by an older woman who can do her job forever?”', 'doja-cat-says-she-s-tickled-by-madonna-trolls-you-feel-threatened-by-an-older-woman-who-can-do-her-j', 'Doja Cat has defended Madonna against trolls, saying she’s “tickled” by people who “feel threatened by an older woman who can do her job forever”. READ MORE: Madonna on the cover: ”People pick on me. That’s just the way it is” The popstar and rapper took to TikTok to discuss claims that Madonna was “too old” to be on stage, saying she was “tickled and bothered” by such comments. “It’s interesting to me because you’re telling a musician who makes...', 'https://www.nme.com/news/music/doja-cat-says-shes-tickled-by-madonna-trolls-you-feel-threatened-by-an-older-woman-who-can-do-her-job-forever-3939303?utm_source=rss&utm_medium=rss&utm_campaign=doja-cat-says-shes-tickled-by-madonna-trolls-you-feel-threatened-by-an-older-woman-who-can-do-her-job-forever', 'https://www.nme.com/wp-content/uploads/2026/04/Doja-Cat-Madonna-2026.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-09 12:35:04', '2026-04-09 22:18:18.022', '2026-04-09 22:18:18.022', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmns1gbop000dwshp21jx8o3b', 'Anne Hathaway based her ‘Mother Mary’ performance on Taylor Swift', 'anne-hathaway-based-her-mother-mary-performance-on-taylor-swift', 'The director of new A24 film Mother Mary has said that Anne Hathaway’s lead character was heavily influenced by Taylor Swift. READ MORE: Taylor Swift – ‘The Life Of A Showgirl’ review The thriller, released April 24 in the UK, stars Hathaway alongside Michaela Coel. The official synopsis reads: “The film follows the psychosexual affair between pop singer Mary (Hathaway) and fashion designer Sam (Coel) after the former’s need for a dress for her new tour draws them back together.”...', 'https://www.nme.com/news/film/anne-hathaway-based-her-mother-mary-performance-on-taylor-swift-3939308?utm_source=rss&utm_medium=rss&utm_campaign=anne-hathaway-based-her-mother-mary-performance-on-taylor-swift', 'https://www.nme.com/wp-content/uploads/2026/04/Anee-Hathaway-Mother-Mary.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-09 12:11:04', '2026-04-09 22:18:18.025', '2026-04-09 22:18:18.025', false, NULL, NULL);
