INSERT INTO "NewsArticle" VALUES ('cmns1gbos000ewshpwofl3qsc', '‘Grand Theft Auto 6’ will feature rapper Freddie Gibbs, according to a new report', 'grand-theft-auto-6-will-feature-rapper-freddie-gibbs-according-to-a-new-report', 'Rapper Freddie Gibbs is the latest musician rumoured to be involved in Grand Theft Auto 6. READ MORE: The best games to play while you wait for ‘Grand Theft Auto 6’ Speaking to PCGamer, journalist and content creator HipHopGamer claimed “there are things in Grand Theft Auto that I know for a fact, because I got a chance to party with Rockstar.” He went on to tease that “a major rapper that left CM Punk bloody by accident,” will feature...', 'https://www.nme.com/news/gaming-news/grand-theft-auto-6-rapper-freddie-gibbs-soundtrack-mission-3939305?utm_source=rss&utm_medium=rss&utm_campaign=grand-theft-auto-6-rapper-freddie-gibbs-soundtrack-mission', 'https://www.nme.com/wp-content/uploads/2026/04/Freddie-Gibbs.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-09 11:45:50', '2026-04-09 22:18:18.028', '2026-04-09 22:18:18.028', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmns1gbqh000fwshptc323quj', 'Gorillaz announce first ever India shows', 'gorillaz-announce-first-ever-india-shows', 'Gorillaz have announced their first ever shows in India. READ MORE: Gorillaz – ‘The Mountain’ review: a world-building ode to death and starting over Damon Albarn, Jamie Hewlett and co. are set to visit India in 2027 for their latest album ‘The Mountain‘, which was mostly recorded in the country. The band will perform at District Arena at Terraform in Bengaluru on January 23. Then, they’ll travel to Mumbai, hosting a show at Jio World Garden in the Bandra Kurla...', 'https://www.nme.com/news/music/gorillaz-announce-first-ever-india-shows-3939291?utm_source=rss&utm_medium=rss&utm_campaign=gorillaz-announce-first-ever-india-shows', 'https://www.nme.com/wp-content/uploads/2026/04/GORILLAZ-Cardiff-20260327-PHOTO-CREDIT-Will-Bailey_044-1.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-09 11:34:59', '2026-04-09 22:18:18.089', '2026-04-09 22:18:18.089', false, NULL, NULL);
INSERT INTO "NewsArticle" VALUES ('cmns1gbql000gwshp0v2oj8eq', '‘SNL UK’ pokes fun at Kanye West Wireless controversy', 'snl-uk-pokes-fun-at-kanye-west-wireless-controversy', 'A promo for SNL UK has poked fun at the Kanye West Wireless Festival controversy. The rapper, now known as Ye, was confirmed last week to be the headliner for all three nights of the London festival, and the gigs were advertised as a journey through his “most iconic records”. The booking sparked widespread criticism due to Ye’s history of anti-Semitism, and Prime Minister Sir Keir Starmer said that it was “deeply concerning” that the rapper had been booked despite...', 'https://www.nme.com/news/tv/snl-uk-pokes-fun-at-kanye-west-wireless-controversy-3939287?utm_source=rss&utm_medium=rss&utm_campaign=snl-uk-pokes-fun-at-kanye-west-wireless-controversy', 'https://www.nme.com/wp-content/uploads/2026/04/kanye-image.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-09 11:09:35', '2026-04-09 22:18:18.093', '2026-04-09 22:18:18.093', false, NULL, NULL);
