INSERT INTO "NewsArticle" VALUES ('cmnvoxab7000ewvhphu6rgigc', 'Jozzy Says Jack Harlow Asked Her Not To Take Credit On Their Collaborations: “We Never Worked After That”', 'jozzy-says-jack-harlow-asked-her-not-to-take-credit-on-their-collaborations-we-never-worked-after-th', 'Last month, Jack Harlow released his new album Monica, which ventured into R&B. About it, he said, "I got Blacker," and received criticism from Cam''ron, Charlamagne Tha God, and other figures in the hip-hop community. Now, Jozzy says the rapper asked her not to take credit on collaborations they were beginning to work on. The post Jozzy Says Jack Harlow Asked Her Not To Take Credit On Their Collaborations: “We Never Worked After That” appeared first on Stereogum.', 'https://stereogum.com/2495512/jozzy-says-jack-harlow-asked-her-not-to-take-credit-on-their-collaborations-we-never-worked-after-that/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/jozzy.jpg', true, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-11 19:30:09', '2026-04-12 11:38:39.091', '2026-04-12 12:53:08.091', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxfz5000pwvhp6bwpst75', 'The 5 Best Songs Of The Week', 'the-5-best-songs-of-the-week', 'Every week the Stereogum staff chooses the five best new songs of the week. The eligibility period begins and ends Thursdays right before midnight. You can hear this week’s picks below and on Stereogum’s Favorite New Music Spotify playlist, which is updated weekly. (An expanded playlist of our new music picks is available to members on Spotify and Apple Music, updated throughout the week.) The post The 5 Best Songs Of The Week appeared first on Stereogum.', 'https://stereogum.com/2495356/the-5-best-songs-of-the-week-621/lists/the-5-best-songs-of-the-week/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/5best_a909fd.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 17:01:38', '2026-04-12 11:38:46.433', '2026-04-12 11:38:46.433', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxgbf000qwvhpi3obr6ia', 'The Rolling Stones Signal Summer Album With New Single “Rough And Twisted”', 'the-rolling-stones-signal-summer-album-with-new-single-rough-and-twisted', 'Posters promoting a band called the Cockroaches have appeared around the north London neighborhood of Camden Town. The group is releasing a vinyl-only white label single called "Rough And Twisted" this Saturday, and they have a website where you can sign up for more info and buy a T-shirt that reads "WHO THE FUCK ARE THE COCKROACHES?" According to a new feature in the Times of London, it''s just the Rolling Stones in disguise, and all this is a warning...', 'https://stereogum.com/2495438/the-rolling-stones-signal-summer-album-with-new-single-rough-and-twisted/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/The-Cockroaches-record.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 15:48:23', '2026-04-12 11:38:46.875', '2026-04-12 11:38:46.875', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxgud000rwvhpmrc0u71g', 'Isaiah Rashad – “Same Sh!t”', 'isaiah-rashad-same-sh-t', 'Isaiah Rashad is back among us. It’s been nearly five years since the elusive Chattanooga rap great released The House Is Burning, his most recent album. It’s been about four years since Rashad was the victim of a terrible invasion of privacy when a sex tape leaked. Earlier this week, Rashad announced a new album… The post Isaiah Rashad – “Same Sh!t” appeared first on Stereogum.', 'https://stereogum.com/2495434/isaiah-rashad-same-sht/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Isaiah-Rashad-Same-Shit.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 15:33:28', '2026-04-12 11:38:47.557', '2026-04-12 11:38:47.557', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxhat000swvhp3fdbj1mb', 'Ava Mendoza Announces New Album Alive Alone, Alive Together: Hear “Dust From The Mines”', 'ava-mendoza-announces-new-album-alive-alone-alive-together-hear-dust-from-the-mines', 'Brooklyn-based guitarist Ava Mendoza is always getting up to something interesting. Last year we highlighted her work with Bill Orcutt Guitar Quartet and Mama Killa, a wild record she made with gabby fluke-mogul and Carolina Pérez. Today comes news of Alive Alone, Alive Together, a new Mendoza album that features legendary jazz drummer Hamid Drake… The post Ava Mendoza Announces New Album <em>Alive Alone, Alive Together</em>: Hear “Dust From The Mines” appeared first on Stereogum.', 'https://stereogum.com/2495431/ava-mendoza-announces-new-album-alive-alone-alive-together-hear-dust-from-the-mines/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/AvaMendoza_AliveAloneAliveTogether.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 15:17:54', '2026-04-12 11:38:48.149', '2026-04-12 11:38:48.149', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxi4x000twvhpdqo73w6m', 'Lily Allen Is Back On Cameo, Will Do Any “Dumb Shit” You Ask For', 'lily-allen-is-back-on-cameo-will-do-any-dumb-shit-you-ask-for', 'UK pop queen Lily Allen roared back into the headlines with the release of last year''s messy, brilliant breakup album West End Girl, and she''s on a big North American tour right now. She''s doing great! But performing at Radio City Music Hall is hard work, and it''s probably a lot easier to make a few hundred bucks by sending someone a quick video message. Perhaps that''s why Lily Allen is back on Cameo. The post Lily Allen Is Back...', 'https://stereogum.com/2495424/lily-allen-is-back-on-cameo-will-do-any-dumb-shit-you-ask-for/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Lily-Allen.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 15:01:34', '2026-04-12 11:38:49.233', '2026-04-12 11:38:49.233', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxibb000uwvhpy0obaz7l', 'Willow Avalon Announces New Album Pink Pocket Pistol: Hear “Cardinal Sin” (Feat. Jason Isbell)', 'willow-avalon-announces-new-album-pink-pocket-pistol-hear-cardinal-sin-feat-jason-isbell', 'Willow Avalon snagged none other than Jason Isbell for her new duet. “Cardinal Sin,” from the Georgia-born country singer’s forthcoming Pink Pocket Pistol, is about a marriage falling apart due to infidelity. They sought a ’60s country feel for the album, and in pursuit of that vision here they deployed a string section and an… The post Willow Avalon Announces New Album <em>Pink Pocket Pistol</em>: Hear “Cardinal Sin” (Feat. Jason Isbell) appeared first on Stereogum.', 'https://stereogum.com/2495423/willow-avalon-cardinal-sin-feat-jason-isbell/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Pink-Pocket-Pistol.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 14:57:37', '2026-04-12 11:38:49.463', '2026-04-12 11:38:49.463', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxisa000vwvhpim2gwfuh', 'Charli XCX Watches Snuff Film, Speaks In American Accent In Faces Of Death Clip', 'charli-xcx-watches-snuff-film-speaks-in-american-accent-in-faces-of-death-clip', 'Faces Of Death looks like a fucked-up movie. The new horror flick is an adaptation of an old cult series of videos that were widely suspected to be actual snuff films in the ''80s. It opens in theaters today, and it''s director Daniel Goldhaber''s follow-up to the fucking awesome 2022 movie How To Blow Up A Pipeline. Former Euphoria star Barbie Ferreira, who''s also in the upcoming indie rock rom-com Mile End Kicks, stars as a content moderator in a...', 'https://stereogum.com/2495412/charli-xcx-watches-snuff-film-speaks-in-american-accent-in-faces-of-death-clip/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Faces-Of-Death.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 14:25:51', '2026-04-12 11:38:50.074', '2026-04-12 11:38:50.074', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxj4b000wwvhpdx6fzveo', 'Mei Semones & Her Dad Team Up On New Song “Kurage”', 'mei-semones-her-dad-team-up-on-new-song-kurage', 'Kurage, the new EP from Artist To Watch Mei Semones, comprises three collaborations. We heard her join forces with Liana Flores on “Koneko” and John Roseboro on “Tooth Fairy.” With the project’s full release today, we’re privy to the song she made with her dad. Don Semones is the featured guest on “Kurage,” the new… The post Mei Semones & Her Dad Team Up On New Song “Kurage” appeared first on Stereogum.', 'https://stereogum.com/2495418/mei-semones-her-dad-team-up-on-new-song-kurage/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Kurage-Lead-Photo-meisemones-@alllywei-15-2.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 14:19:57', '2026-04-12 11:38:50.507', '2026-04-12 11:38:50.507', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxjgo000xwvhphrge0cwe', 'Coma Regalia – “Guitar And Video Games” (Sunny Day Real Estate Cover)', 'coma-regalia-guitar-and-video-games-sunny-day-real-estate-cover', 'I’m on record declaring Sunny Day Real Estate’s How It Feels To Be Something On as the best album of 1998. Does that statement stand up to scrutiny? Probably not, but it feels right whenever I’m listening. SDRE LP3 is a stone-cold classic, a record everyone who loves ambitious, arena-scale, artsy-but-accessible rock music should be… The post Coma Regalia – “Guitar And Video Games” (Sunny Day Real Estate Cover) appeared first on Stereogum.', 'https://stereogum.com/2495410/coma-regalia-guitar-and-video-games-sunny-day-real-estate-cover/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/a0997896169_10.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 13:56:51', '2026-04-12 11:38:50.952', '2026-04-12 11:38:50.952', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxk8b000ywvhptozqlhzx', 'Sufjan Stevens’ Piss Poems Unearthed After More Than 25 Years', 'sufjan-stevens-piss-poems-unearthed-after-more-than-25-years', 'Sufjan Stevens is a man of mystery, and little bits of his lore seem to surface in the most unpredictable ways. In 2016, for instance, the Dallas musician Marc Rebillet posted about finding an unreleased 1998 album called Stalker in Stevens'' dumpster. (We interviewed Rebillet, naturally.) Now, a Penn State undergrad has posted on TikTok about the apparent discovery of a Stevens poetry chapbook called Piss Poems. The post Sufjan Stevens’ <em>Piss Poems</em> Unearthed After More Than 25 Years appeared...', 'https://stereogum.com/2495390/sufjan-stevens-piss-poems-unearthed-after-more-than-25-years/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/piss-poems.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 13:43:21', '2026-04-12 11:38:51.947', '2026-04-12 11:38:51.947', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxkkr000zwvhpdatkq2pc', 'Foo Fighters – “Of All People”', 'foo-fighters-of-all-people', '“Of all people, you survived/ When no one else could stay alive/ You know you should be dead/ But you’re alive instead.” So begins “Of All People,” the new Foo Fighters single. The band debuted it in a taping of the Irish TV show Other Voices back in February; the episode finally aired this week,… The post Foo Fighters – “Of All People” appeared first on Stereogum.', 'https://stereogum.com/2495397/foo-fighters-of-all-people/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed.gif', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 13:35:34', '2026-04-12 11:38:52.395', '2026-04-12 11:38:52.395', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxl1k0010wvhpwb5d4u1u', 'Alabama Shakes – “American Dream”', 'alabama-shakes-american-dream', 'Blues-rock stars Alabama Shakes made a surprise return at the end of 2024, playing an unannounced reunion set at a Tuscaloosa benefit — their first time playing live in seven years. They’ve been touring hard since then. Last year, they shared “Another Life,” their first new song in ten years. Right now, they’re at work… The post Alabama Shakes – “American Dream” appeared first on Stereogum.', 'https://stereogum.com/2495395/alabama-shakes-american-dream/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Alabama-Shakes.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 13:21:53', '2026-04-12 11:38:53', '2026-04-12 11:38:53', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxle60011wvhpkobsagvm', 'flirty800 Announces New EP Strip: Hear “Smoke”', 'flirty800-announces-new-ep-strip-hear-smoke', 'flirty800 is the project of New York-based producer and DJ Wade Harley Harris, who’s done sets at Basement, Paragon, and the Lot Radio. Last year, he released his debut EP My Mind, which was grungy and dark (he described the vibe as “slut grunge summer“). Now he’s announcing its followup Strip, whose lead single “Smoke”… The post flirty800 Announces New EP <em>Strip</em>: Hear “Smoke” appeared first on Stereogum.', 'https://stereogum.com/2495381/flirty800-announces-new-ep-strip-hear-smoke/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/image-4.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 01:56:01', '2026-04-12 11:38:53.454', '2026-04-12 11:38:53.454', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxlr40012wvhpbzmmwcks', 'Lady Gaga & Doechii – “Runway”', 'lady-gaga-doechii-runway', 'Last year, Doechii presented Gaga with the Innovator Award at the iHeartRadio Music Awards. Now the rising rapper is joining forces with the pop icon for “Runway,” which was first previewed in the trailer for The Devil Wears Prada 2. The track was written by Gaga, Bruno Mars, Jaylah Hickmon, Andrew Watt, Henry Walter, Dernst “D’Mile”… The post Lady Gaga & Doechii – “Runway” appeared first on Stereogum.', 'https://stereogum.com/2495377/lady-gaga-doechii-runway/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-38.png', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 00:31:19', '2026-04-12 11:38:53.92', '2026-04-12 11:38:53.92', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxm5a0013wvhpghqozzfp', 'Tasha – “Summer”', 'tasha-summer', 'It’s not yet summer, but it’s always time for a wistful ballad about the hot, decadent season. Tasha is supplying us with that today with her new All This And So Much More single “Summer.” “‘Summer’ was written in June of 2024 in the middle of my Broadway run with Illinoise,” the singer-songwriter explains, referring… The post Tasha – “Summer” appeared first on Stereogum.', 'https://stereogum.com/2495371/tasha-summer/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-37.png', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 23:10:09', '2026-04-12 11:38:54.43', '2026-04-12 11:38:54.43', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxmoa0014wvhpb8t99168', 'Pacha New York Announces Opening In The Wake Of Brooklyn Mirage Fiasco', 'pacha-new-york-announces-opening-in-the-wake-of-brooklyn-mirage-fiasco', 'In February, it was reported that the Brooklyn Mirage was planning to reopen in June with a new name after being acquired by the Dubai-based company FIVE Holdings. The troubled East Williamsburg venue started working on security improvements in December 2024, which led to many botched reopenings, demolition plans, a fired CEO. Now, the Brooklyn Mirage is officially called Pacha New York, and the opening weekend has been announced. The post Pacha New York Announces Opening In The Wake Of...', 'https://stereogum.com/2495366/pacha-new-york-announces-opening-in-the-wake-of-brooklyn-mirage-fiasco/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-36.png', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 22:36:46', '2026-04-12 11:38:55.114', '2026-04-12 11:38:55.114', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxn0k0015wvhptb9auxs0', 'Lip Critic – “Talon”', 'lip-critic-talon', 'Lip Critic’s Theft World is shaping to be as wild as its premise. The album was allegedly inspired by a real-life theft of frontman Bret Kaser’s identity by a fan who was convinced Lip Critic’s music contained clues for an elaborate scavenger hunt. Early singles “Legs In A Snare” and “Jackpot” have fleshed out the… The post Lip Critic – “Talon” appeared first on Stereogum.', 'https://stereogum.com/2495351/lip-critic-talon/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/LIPCIRITC_04_603-1.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 20:39:59', '2026-04-12 11:38:55.556', '2026-04-12 11:38:55.556', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxnc40016wvhp0eqkkgle', 'Afrika Bambaataa Dead At 67', 'afrika-bambaataa-dead-at-67', 'Afrika Bambaataa, the hip-hop pioneer who was successfully sued for child sex trafficking later in life, is dead. Bambaataa died around 3 a.m. today in Pennsylvania due to complications from cancer, TMZ reports. He was 67. Bambaataa is one of the great confounding figures of rap history. For decades, he was a mythic figure, and…', 'https://stereogum.com/2495346/afrika-bambaataa-dead-at-67/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/GettyImages-1398799297.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 19:59:37', '2026-04-12 11:38:55.972', '2026-04-12 11:38:55.972', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxnwe0017wvhpv8tjn1ql', 'Mary Halvorson & Ambrose Akinmusire Announce New Album Slo-Mo Neon Luminate Hoverings: Hear “Soundcheck”', 'mary-halvorson-ambrose-akinmusire-announce-new-album-slo-mo-neon-luminate-hoverings-hear-soundcheck', 'Slo-Mo Neon Luminate Hoverings brings together two giants of modern jazz and experimental music, trumpeter Ambrose Akinmusire and guitarist Mary Halvorson. The pair will release the record in June via Nonesuch, representing the culmination of sporadic collaborations dating all the way back to 2009. This material specifically was hashed out in January 2025, performed at… The post Mary Halvorson & Ambrose Akinmusire Announce New Album <em>Slo-Mo Neon Luminate Hoverings</em>: Hear “Soundcheck” appeared first on Stereogum.', 'https://stereogum.com/2495342/mary-halvorson-ambrose-akinmusire-announce-new-album-slo-mo-neon-luminate-hoverings-hear-soundcheck/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/a3814511741_10.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 19:48:56', '2026-04-12 11:38:56.702', '2026-04-12 11:38:56.702', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxo8j0018wvhpzi18nou6', 'Kelsey Lu – “Portrait Of A Lady On Fire”', 'kelsey-lu-portrait-of-a-lady-on-fire', 'Portrait Of A Lady On Fire — excellent movie! That’s also the title of the also-excellent new single from Kelsey Lu, whose new album So Help Me God is coming out this June (we really liked its lead single “Running To Pain“). “Portrait Of A Lady On Fire” is a cello-embellished synth ballad with a sort… The post Kelsey Lu – “Portrait Of A Lady On Fire” appeared first on Stereogum.', 'https://stereogum.com/2495325/kelsey-lu-portrait-of-a-lady-on-fire/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Photo-credit_-Yumna-Al-Arashi-.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 18:58:21', '2026-04-12 11:38:57.139', '2026-04-12 11:38:57.139', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxoku0019wvhpfgiuys03', 'Tom DeLonge Showed Trent Reznor A Photo Of A Dead Alien At Foo Fighters Drummer’s Wedding', 'tom-delonge-showed-trent-reznor-a-photo-of-a-dead-alien-at-foo-fighters-drummer-s-wedding', 'That headline is a wild ride, right? A lot to unpack there. The important information is all up there. Rock stars are getting together and showing each other pictures of dead aliens. 
INSERT INTO "NewsArticle" VALUES ('cmnvoxp66001awvhp1u2ooypz', 'Yasmin Williams Shares Her First Documentary Soundtrack Saving Etting Street', 'yasmin-williams-shares-her-first-documentary-soundtrack-saving-etting-street', 'Baltimore is a city full of vacant, decaying houses — places that could be real homes if the building and surrounding neighborhoods were properly rebuilt. That’s the subject of a new documentary called Saving Etting Street. The film, which is currently on the festival circuit, is about the efforts of Shelley Halstead, a carpenter who… The post Yasmin Williams Shares Her First Documentary Soundtrack <em>Saving Etting Street</em> appeared first on Stereogum.', 'https://stereogum.com/2495328/yasmin-williams-shares-her-first-documentary-soundtrack-saving-etting-street/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Yasmin-Williams-Saving-Etting-Street.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 17:56:26', '2026-04-12 11:38:58.35', '2026-04-12 11:38:58.35', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxpr9001bwvhponmhfnn3', 'KATSEYE Share New Single “Pinky Up” Amid Manon Drama', 'katseye-share-new-single-pinky-up-amid-manon-drama', 'The LA-based girl group KATSEYE functions as a grand experiment, a chance to see whether the K-pop idol model will work in the US and across the rest of the world. In some ways, it’s a tremendous success. KATSEYE have made a lot of social-media noise, and they’ve got a few genuine viral hits. They… The post KATSEYE Share New Single “Pinky Up” Amid Manon Drama appeared first on Stereogum.', 'https://stereogum.com/2495322/katseye-share-new-single-pinky-up-amid-manon-drama/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/KATEYE.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 17:24:23', '2026-04-12 11:38:59.109', '2026-04-12 11:38:59.109', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxpxt001cwvhpomzy45ry', 'Arlo Parks Covers PinkPantheress’ “Stateside” In The Live Lounge', 'arlo-parks-covers-pinkpantheress-stateside-in-the-live-lounge', 'PinkPantheress'' Fancy That highlight "Stateside" has been getting a ton of play over the past few weeks since gold medalist figure skater Alysa Liu picked the Zara Larsson remix for her program at the Olympic Exhibition Gala back in February. Pink''s fellow Brit Arlo Parks recently stopped by the BBC Radio 1 live lounge, where she performed her own dreamy rendition of "Stateside" with a trio of synths, a guitar, and bass. The song simply must be sung with a...', 'https://stereogum.com/2495309/arlo-parks-covers-pinkpantheress-stateside-in-the-live-lounge/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/vnNvUc__U0k-HD.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 16:53:38', '2026-04-12 11:38:59.345', '2026-04-12 11:38:59.345', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxqao001dwvhp51colot9', 'Skylar Spence Shares New 22-Minute Mix “Almost Butterflies” To Go With Hit Vibes Reissue', 'skylar-spence-shares-new-22-minute-mix-almost-butterflies-to-go-with-hit-vibes-reissue', 'When we last heard from Skylar Spence last summer, the artist formerly known as Saint Pepsi was celebrating the 10th anniversary of his 2015 classic Prom King. Now it seems he’s adopted a forward-looking posture, at least partially. Spence shared a new 22-minute mix on YouTube and Bandcamp today called “Almost Butterflies.” It’s a fizzy,… The post Skylar Spence Shares New 22-Minute Mix “Almost Butterflies” To Go With <em>Hit Vibes</em> Reissue appeared first on Stereogum.', 'https://stereogum.com/2495316/skylar-spence-shares-new-22-minute-mix-almost-butterflies-to-go-with-hit-vibes-reissue/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/a2888711757_10.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 16:19:30', '2026-04-12 11:38:59.808', '2026-04-12 11:38:59.808', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxqnc001ewvhpcwxnfddq', 'The Sequence’s Gwendolyn “Blondy” Chisolm Dead At 66', 'the-sequence-s-gwendolyn-blondy-chisolm-dead-at-66', 'Gwendolyn “Blondy” Chisolm, a member of the extremely early all-female rap trio the Sequence, has passed away. Billboard reports that Chisolm died in Atlanta on Monday after a brief illness. She was 66. Her death follows that of Angie Stone, the former Sequence member who rapped as Angie B long before becoming a star in the late-''90s neo-soul wave, and that leaves Cheryl "The Pearl" Cook as the sole surviving member of the Sequence. The post The Sequence’s Gwendolyn “Blondy”...', 'https://stereogum.com/2495310/the-sequences-gwendolyn-blondy-chisolm-dead-at-66/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Sequence.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 15:48:18', '2026-04-12 11:39:00.264', '2026-04-12 11:39:00.264', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvz2rbd002gwvhpmmusgg31', 'Justin Bieber reconnects with fans at Coachella', 'justin-bieber-reconnects-with-fans-at-coachella', 'With a minimalist set and a trip through his musical past, pop superstar Justin Bieber returned to the stage on Saturday night to headline the second day of the Coachella festival in Indio, California.', 'https://www.rte.ie/entertainment/2026/0412/1567820-justin-bieber-reconnects-with-fans-at-coachella/', 'https://www.rte.ie/images/00243376-1600.jpg', false, false, NULL, 'cmns3qc5u0000idhpe8f9i7uq', '2026-04-12 11:55:59', '2026-04-12 16:22:50.569', '2026-04-12 16:22:50.569', false, 'via RTE Music', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxqyn001fwvhplbd1mtuk', 'Johnny Marr Joins Pet Shop Boys For Some Oldies They’d Never Performed Before', 'johnny-marr-joins-pet-shop-boys-for-some-oldies-they-d-never-performed-before', 'UK legends Johnny Marr and the Pet Shop Boys go way, way back together. According to a 2009 Guardian story, Marr met the Pet Shop Boys by chance in a Los Angeles hotel elevator in 1987, just after he left the Smiths, and he told them how much he liked their song "Hit Music." PSB singer Neil Tennant appeared on "Getting Away With It," the 1989 debut single from Electronic, Marr''s post-Smiths duo with New Order''s Bernard Sumner, and on...', 'https://stereogum.com/2495302/johnny-marr-joins-pet-shop-boys-for-some-oldies-theyd-never-performed-before/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Pet-Shop-boys.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 15:07:05', '2026-04-12 11:39:00.671', '2026-04-12 11:39:00.671', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxrat001gwvhpsaq9wqq0', 'Jejune Announce First US Shows Since The ’90s', 'jejune-announce-first-us-shows-since-the-90s', 'Jejune: A great band, and one who — up until recently — you had to scour niche corners of the internet to listen to. The great archival record label Numero Group, however, has been reissuing the San Diego-via-Boston emo band''s catalog, culminating into one big box set called Wait A Lifetime that arrives this June. They''ll also be playing some of that music on the road this year with their very first US shows since their initial run in the...', 'https://stereogum.com/2495290/jejune-announce-first-us-shows-since-the-90s/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Jejune.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-09 15:00:34', '2026-04-12 11:39:01.109', '2026-04-12 11:39:01.109', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvoxbz6000hwvhp7liubd2i', 'Sabrina Carpenter’s Hollywood-Themed Coachella Set Had Susan Sarandon, Will Ferrell, Sam Elliott, & More', 'sabrina-carpenter-s-hollywood-themed-coachella-set-had-susan-sarandon-will-ferrell-sam-elliott-more', 'Today marks exactly two years since Sabrina Carpenter''s rise into main-girl pop stardom with "Espresso." Before that song, the idea of her headlining Coachella would''ve been ridiculous, but now it''s a given. She did just that last night, and her Hollywood-themed performance included appearances from various actors, plus several Man''s Best Friend live debuts. The post Sabrina Carpenter’s Hollywood-Themed Coachella Set Had Susan Sarandon, Will Ferrell, Sam Elliott, & More appeared first on Stereogum.', 'https://stereogum.com/2495491/sabrina-carpenters-coachella-set-had-susan-sarandon-will-ferrell-several-mans-best-friend-live-debuts/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/sabrina-carpenter.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-11 16:03:56', '2026-04-12 11:38:41.25', '2026-04-12 12:52:46.603', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmns1gbuv000iwshpgadlx4q8', 'Afrika Bambaataa Dies at 67', 'afrika-bambaataa-dies-at-67', 'The pioneering hip-hop DJ and Zulu Nation founder had, in his last decade, been accused by multiple men of sexually abusing them when they were teenagers', 'https://pitchfork.com/news/afrika-bambaataa-dies-at-67/', 'https://media.pitchfork.com/photos/69d7fd3e10afb63f4e61303e/16:9/w_1280,c_limit/GettyImages-85002069.jpg', false, false, NULL, 'cmnkctw1m000jplhpezzt5352', '2026-04-09 21:34:18', '2026-04-09 22:18:18.247', '2026-04-12 12:53:01.796', false, NULL, NULL);
