INSERT INTO "NewsArticle" VALUES ('cmnuwokjj0075wrhpgk009ih7', 'Watch Dijon Bring Out Mk.gee at Coachella 2026', 'watch-dijon-bring-out-mk-gee-at-coachella-2026', 'The Baby artist made his festival debut at the Outdoor Stage on Friday', 'https://pitchfork.com/news/watch-dijon-bring-out-mkgee-at-coachella-2026/', 'https://media.pitchfork.com/photos/69daadcce5a162acc606839f/16:9/w_1280,c_limit/GettyImages-2270345287.jpg', true, false, NULL, 'cmnkctw1m000jplhpezzt5352', '2026-04-11 21:12:58', '2026-04-11 22:28:03.199', '2026-04-12 12:53:05.386', false, 'via Pitchfork', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvmcm8n0003wvhplhxt2c2d', 'Legendary Indian singer Asha Bhosle dies aged 92', 'legendary-indian-singer-asha-bhosle-dies-aged-92', 'Legendary Indian playback singer Asha Bhosle, whose voice defined Bollywood music through the 1970s and 80s, has died in Mumbai aged 92, her family has said.', 'https://www.rte.ie/entertainment/2026/0412/1567809-legendary-indian-singer-asha-bhosle-dies-aged-92/', 'https://www.rte.ie/images/00243365-1600.jpg', false, false, NULL, 'cmns3qc5u0000idhpe8f9i7uq', '2026-04-12 10:22:38', '2026-04-12 10:26:35.543', '2026-04-12 12:53:06.389', false, 'via RTE Music', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvox9yc000dwvhpwmdfeus4', 'NewJeans’ Danielle Previews New Solo Music Amid ADOR Lawsuit', 'newjeans-danielle-previews-new-solo-music-amid-ador-lawsuit', 'Earlier this year, NewJeans'' Danielle gave an update to fans as she''s been entangled in a heated legal battle with South Korean label ADOR for over a year. It escalated in December when ADOR terminated and sued her, one-fifth of the K-pop group. Now, she''s teasing new solo music. 
INSERT INTO "NewsArticle" VALUES ('cmnvmcpk90005wvhpl4sjqj01', 'Watch Justin Bieber revisit his earliest hits and bring out The Kid Laroi, Tems, Mk.gee, Wizkid and Dijon during comeback Coachella set', 'watch-justin-bieber-revisit-his-earliest-hits-and-bring-out-the-kid-laroi-tems-mk-gee-wizkid-and-dij', 'Justin Bieber made his long-awaited return to the stage at Coachella. Find out everything that went down below. READ MORE: Justin Bieber – ‘Swag’ review: fascinating sounds with little lyrical depth Announced back in September, Bieber’s headline set signalled his return to performing for the first time in the US since his 2022 ‘Justice’ world tour. In the meantime, he’s performed at the Grammys and, last month, played a surprise, intimate warm-up show in Los Angeles. Last night (April 11),...', 'https://www.nme.com/news/music/watch-justin-bieber-revisit-his-earliest-hits-and-bring-out-the-kid-laroi-tems-mk-gee-wizkid-and-dijon-during-comeback-coachella-set-3939768?utm_source=rss&utm_medium=rss&utm_campaign=watch-justin-bieber-revisit-his-earliest-hits-and-bring-out-the-kid-laroi-tems-mk-gee-wizkid-and-dijon-during-comeback-coachella-set', 'https://www.nme.com/wp-content/uploads/2026/04/Justin-Bieber-performs-at-the-2026-Grammys.-CREDIT_-Kevin-Winter_Getty-Images-for-The-Recording-Academy.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 09:25:53', '2026-04-12 10:26:39.849', '2026-04-12 12:53:07.16', false, 'via NME', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvmcpkk0007wvhpzrrhvznv', 'Watch Sombr surprise fans with Billy Corgan to duet Smashing Pumpkins ‘1979’ at Coachella', 'watch-sombr-surprise-fans-with-billy-corgan-to-duet-smashing-pumpkins-1979-at-coachella', 'Sombr surprised fans during his Coachella set with a surprise duet with Billy Corgan. READ MORE: Sombr tells us “music from the UK beats” the US at the BRITs 2026 The moment came during Sombr’s sunset set at the Outdoor Theatre yesterday (April 11), where he performed a slew of fan-favourite hits as well as delivering the live debut of a new track ‘Potential’. Halfway through the set, he brought out Corgan, marking the Smashing Pumpkins frontman’s first ever time...', 'https://www.nme.com/news/music/watch-sombr-surprise-fans-with-billy-corgan-to-duet-smashing-pumpkins-1979-at-coachella-3939760?utm_source=rss&utm_medium=rss&utm_campaign=watch-sombr-surprise-fans-with-billy-corgan-to-duet-smashing-pumpkins-1979-at-coachella', 'https://www.nme.com/wp-content/uploads/2026/04/Sombr.-CREDIT_-Frazer-Harrison_Getty-Images-for-Coachella.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 08:41:17', '2026-04-12 10:26:39.86', '2026-04-12 12:53:08.076', false, 'via NME', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvz2o21002ewvhpr6ad8bg1', 'Former Turnstile & The S.E.T. Guitarist Kicked Out Of Another Band After Attempted Murder Charge', 'former-turnstile-the-s-e-t-guitarist-kicked-out-of-another-band-after-attempted-murder-charge', 'Brady Ebert, former guitarist of Turnstile and the S.E.T., has now been kicked out of another band following this month’s news that he was charged with attempted murder of Turnstile frontman Brendan Yates’ father. Ebert co-founded the hardcore project Experience with Bobby Faithful and Ben Rogers earlier this year, and they’re set to release their…', 'https://stereogum.com/2495548/former-turnstile-the-s-e-t-guitarist-kicked-out-of-another-band-after-attempted-murder-charge/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Brady-Ebert.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-12 15:00:50', '2026-04-12 16:22:46.345', '2026-04-12 16:22:46.345', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvz2oqf002fwvhpkvkz3e5r', 'Geese Make Coachella Debut With Justin Bieber Cover, Sabrina Carpenter Cheers Them On', 'geese-make-coachella-debut-with-justin-bieber-cover-sabrina-carpenter-cheers-them-on', 'Geese enjoy doing covers. A couple of years ago, they recorded a rendition of Justin Bieber''s 2010 single "Baby," and yesterday they happened to play their first-ever Coachella set on the same evening that Bieber headlined. To mark the occasion, Geese debuted a snippet of their "Baby" cover, working it into their 3D Country track "2122." The post Geese Make Coachella Debut With Justin Bieber Cover, Sabrina Carpenter Cheers Them On appeared first on Stereogum.', 'https://stereogum.com/2495545/geese-make-coachella-debut-with-justin-bieber-cover-sabrina-carpenter-cheers-them-on/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Geese.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-12 14:01:04', '2026-04-12 16:22:47.223', '2026-04-12 16:22:47.223', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvz2ta2002iwvhpzwwwjhom', 'No Doubt guitarist Tom Dumont reveals early onset Parkinson’s diagnosis', 'no-doubt-guitarist-tom-dumont-reveals-early-onset-parkinson-s-diagnosis', 'No Doubt guitarist Tom Dumont has revealed that he has been diagnosed with early onset Parkinson’s disease. READ MORE: Gwen Stefani tells us about her yacht rock-influenced solo album ‘Bouquet’ and the future of No Doubt The band are preparing for their first run of shows in 14 years with their residency at The Sphere in Las Vegas, but in a new social media video, Dumont has revealed that he has been living with the “struggle” of his new diagnosis....', 'https://www.nme.com/news/music/no-doubt-guitarist-tom-dumont-reveals-early-onset-parkinsons-diagnosis-3939818?utm_source=rss&utm_medium=rss&utm_campaign=no-doubt-guitarist-tom-dumont-reveals-early-onset-parkinsons-diagnosis', 'https://www.nme.com/wp-content/uploads/2026/04/tom_dumont_nodoubt.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 16:18:16', '2026-04-12 16:22:53.114', '2026-04-12 16:22:53.114', false, 'via NME', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvz2tai002jwvhpdccr5dav', 'Watch Yungblud kick off ‘Idols’ UK arena tour with homecoming show', 'watch-yungblud-kick-off-idols-uk-arena-tour-with-homecoming-show', 'Yungblud returned home to Yorkshire to kick off the UK arena leg of his ‘Idols’ world tour – check out footage below. READ MORE: Yungblud – ‘Idols’ and ‘Idols II’ review: a king-sized statement from the crown prince of rock The Doncaster-born artist – real name Dominic Harrison – played at Sheffield’s Utilita Arena on Saturday night (April 11) for the first of a run of shows that had to be extended last October due to outstanding demand. After a...', 'https://www.nme.com/news/music/watch-yungblud-kick-off-idols-uk-arena-tour-with-homecoming-show-3939814?utm_source=rss&utm_medium=rss&utm_campaign=watch-yungblud-kick-off-idols-uk-arena-tour-with-homecoming-show', 'https://www.nme.com/wp-content/uploads/2026/04/Yungblud_TOM_PALLANT.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 15:42:27', '2026-04-12 16:22:53.13', '2026-04-12 16:22:53.13', false, 'via NME', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnvz2tas002kwvhplidl8yom', 'Watch Addison Rae bring out Maddie Ziegler for ‘Aquamarine’ dance break at Coachella', 'watch-addison-rae-bring-out-maddie-ziegler-for-aquamarine-dance-break-at-coachella', 'Addison Rae brought out Maddie Ziegler as a surprise guest during her debut Coachella set – check out the moment below. READ MORE: Addison Rae live in London: effortless euphoria from a pop icon-in-waiting A year after she announced her debut album during Arca’s set and appeared as a special guest during Charli XCX’s, Rae returned for her solo debut at the Californian festival yesterday (April 11). Ahead of her set, she’d told fans that the show would mark an...', 'https://www.nme.com/news/music/watch-addison-rae-bring-out-maddie-ziegler-for-aquamarine-dance-break-at-coachella-3939785?utm_source=rss&utm_medium=rss&utm_campaign=watch-addison-rae-bring-out-maddie-ziegler-for-aquamarine-dance-break-at-coachella', 'https://www.nme.com/wp-content/uploads/2026/04/Addison-Rae.-CREDIT_-Kevin-Mazur_Getty-Images-for-Coachella.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 10:36:10', '2026-04-12 16:22:53.14', '2026-04-12 16:22:53.14', false, 'via NME', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnw9um81002lwvhpbyu0oau2', 'Anitta Makes SNL Debut, Ben Marshall Parodies Jack Harlow', 'anitta-makes-snl-debut-ben-marshall-parodies-jack-harlow', 'Anitta appeared as the musical guest on Saturday Night Live last night, making her the first ever Brazilian artist to do so. The Rio-born singer performed "Várias Quejas" and the newly-released single "Choka Choka" from her album Equilibrium, which is out this coming Friday. The studio version of "Choka Choka" is a duet with Shakira, who did not appear during Anitta''s SNL performances, but you can watch/listen to both versions below. The post Anitta Makes <em>SNL</em> Debut, Ben Marshall Parodies...', 'https://stereogum.com/2495562/anitta-makes-snl-debut-shares-shakira-collab-choka-choka/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/J_NDtbRAVnQ-HD.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-12 19:47:51', '2026-04-12 21:24:26.497', '2026-04-12 21:24:26.497', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnw9umep002mwvhpzopcw6ls', 'Mike Patton Sings Faith No More With Avett Brothers At AVTT/PTTN Tour Opener', 'mike-patton-sings-faith-no-more-with-avett-brothers-at-avtt-pttn-tour-opener', 'Last fall Faith No More/Mr. Bungle frontman Mike Patton teamed up with Scott and Seth Avett — aka the Avett Brothers — for a rather unexpected new band called AVTT/PTTN, sharing their self-titled debut album back in November. Following a couple of promotional appearances and some canceled gigs, Patton and the Avetts have now officially begun their tour. The tour''s first two nights in Louisville on Friday and Nashville on Saturday saw them play a bunch of live debuts from...', 'https://stereogum.com/2495554/mike-patton-sings-faith-no-more-with-avett-brothers-at-avtt-pttn-tour-opener/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/AVTTPTTN.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-12 18:45:39', '2026-04-12 21:24:26.738', '2026-04-12 21:24:26.738', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnw9umky002nwvhpa15tjeg2', 'Billy Corgan Makes Surprise Coachella Debut With Sombr', 'billy-corgan-makes-surprise-coachella-debut-with-sombr', 'Somehow the Smashing Pumpkins have never played Coachella (maybe it''s the CIA''s fault). But Sombr, who recently linked up onstage with members of fellow ''90s alt-rock legends the Cranberries, took a moment out of his Coachella set on Saturday to bring out Pumpkins frontman Billy Corgan. Together they sang the Mellon Collie And The Infinite Sadness hit "1979," which is having a big moment on TikTok right now. It took a while for Corgan''s mic to start working but they...', 'https://stereogum.com/2495551/billy-corgan-makes-surprise-coachella-debut-with-sombr/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Sombr-BIlly-Corgan.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-12 16:20:21', '2026-04-12 21:24:26.962', '2026-04-12 21:24:26.962', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnw9uq2c002owvhpdr1ujfo0', 'Watch Jack White’s epic early set at Coachella 2026', 'watch-jack-white-s-epic-early-set-at-coachella-2026', 'Jack White played an epic last-minute set at Coachella 2026 this weekend – check out the full setlist and footage from the show below. READ MORE: Jack White – ‘No Name’ review: surprise album is maestro’s punkiest outing since White Stripes The former White Stripes frontman was only named on the bill as a late surprise earlier this week and delivered an hour-long set as the opening act on the Mojave Tent on Saturday (April 11) – exceeding his original...', 'https://www.nme.com/news/music/watch-jack-whites-epic-early-set-at-coachella-2026-3939838?utm_source=rss&utm_medium=rss&utm_campaign=watch-jack-whites-epic-early-set-at-coachella-2026', 'https://www.nme.com/wp-content/uploads/2026/04/jack_white_live.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 19:55:39', '2026-04-12 21:24:31.476', '2026-04-12 21:24:31.476', false, 'via NME', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnw9uq2s002pwvhplyi5u6oe', 'Here’s what The xx played as they made their long-awaited return to Coachella', 'here-s-what-the-xx-played-as-they-made-their-long-awaited-return-to-coachella', 'The xx have played their first show at Coachella in nine years – check out the full setlist and footage from their performance below. READ MORE: Romy on being back in the studio with The xx: “We’re up for trying new things but it sounds like us” The trio have been playing live again for the first time since 2018 in recent weeks, with their return show going down in Mexico City’s Pepsi Center WTC on April 3. On Friday...', 'https://www.nme.com/news/music/heres-what-the-xx-played-as-they-made-their-long-awaited-return-to-coachella-3939830?utm_source=rss&utm_medium=rss&utm_campaign=heres-what-the-xx-played-as-they-made-their-long-awaited-return-to-coachella', 'https://www.nme.com/wp-content/uploads/2026/04/thexx_romy_coachella.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 18:57:33', '2026-04-12 21:24:31.492', '2026-04-12 21:24:31.492', false, 'via NME', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnw9uq2x002qwvhpgrr7ef52', 'Watch The Strokes rock Coachella 2026 as Julian Casablancas makes subtle dig at Jeff Bezos', 'watch-the-strokes-rock-coachella-2026-as-julian-casablancas-makes-subtle-dig-at-jeff-bezos', 'The Strokes have returned to Coachella after a 15-year absence, with Julian Casablancas making a subtle dig at Jeff Bezos – check out footage below. READ MORE: The Strokes’ delicate, sun-kissed comeback single ‘Going Shopping’ is an item you’d try on but wouldn’t buy The NYC indie heroes are preparing to release their Rick Rubin-produced seventh studio album ‘Reality Awaits’ in June (pre-order here) and have already shared the lead single ‘Going Shopping’. On Saturday night (April 11), they took...', 'https://www.nme.com/news/music/watch-the-strokes-rock-coachella-2026-as-julian-casablancas-makes-subtle-dig-at-jeff-bezos-3939826?utm_source=rss&utm_medium=rss&utm_campaign=watch-the-strokes-rock-coachella-2026-as-julian-casablancas-makes-subtle-dig-at-jeff-bezos', 'https://www.nme.com/wp-content/uploads/2026/04/julian_casablancas_strokes.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 18:06:54', '2026-04-12 21:24:31.497', '2026-04-12 21:24:31.497', false, 'via NME', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnw9uq33002rwvhpcepz3esf', 'Asha Bhosle, iconic Bollywood singer, dies aged 92', 'asha-bhosle-iconic-bollywood-singer-dies-aged-92', 'Asha Bhosle, the Bollywood singing icon that recorded with Gorillaz and was the inspiration for Cornershop’s ‘Brimful Of Asha’, has died aged 92. The news was confirmed by her family earlier today (April 12), who said she passed away after being admitted to hospital in Mumbai after suffering from extreme exhaustion and a chest infection. In a long and storied career, she recorded more than 12,000 songs and was one of the most celebrated Indian singers of all time, becoming...', 'https://www.nme.com/news/music/asha-bhosle-iconic-bollywood-singer-dies-aged-92-3939822?utm_source=rss&utm_medium=rss&utm_campaign=asha-bhosle-iconic-bollywood-singer-dies-aged-92', 'https://www.nme.com/wp-content/uploads/2026/04/asha_bhosle_rip.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 16:56:35', '2026-04-12 21:24:31.503', '2026-04-12 21:24:31.503', false, 'via NME', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yeaw0000xphpwkzjm3bb', 'Widowspeak – “No Driver”', 'widowspeak-no-driver', 'Last month we got the fantastic news that Widowspeak are returning with their first new album in four years. The indie folk-rock duo introduced Roses with the eminently enjoyable “If You Change,” and they’ve followed it up another good one called “No Driver.” The guitars are going nuts on these new tracks. “No Driver” essentially… The post Widowspeak – “No Driver” appeared first on Stereogum.', 'https://stereogum.com/2495783/widowspeak-no-driver/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-2026-04-14T171153.383.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 21:24:59', '2026-04-14 22:26:42.536', '2026-04-14 22:26:42.536', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yet00001xphp5nislbvi', 'Album Of The Week: Winston Hightower 100 Acre Wood', 'album-of-the-week-winston-hightower-100-acre-wood', 'Winston Hightower is indisputably punk. That’s not just because he’s been a touring bassist for hardcore bands like Soul Glo, Minority Threat, and Twompsax. The Columbus-born musician first began self-releasing his music over a decade ago, and across countless releases — most of them hard to find these days — Hightower’s career so far has seen him subtly incorporate post-punk, rap, and jazz into his ramshackle indie pop. He’s accrued the type of vast, elusive catalog that seems requisite for...', 'https://stereogum.com/2495758/album-of-the-week-winston-hightower-100-acre-wood/reviews/album-of-the-week/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/100-Acre-Wood.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 19:07:09', '2026-04-14 22:26:43.188', '2026-04-14 22:26:43.188', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yf620002xphph6meirmo', 'Diplo Says Creatives Need To Use AI Or “Give Up”', 'diplo-says-creatives-need-to-use-ai-or-give-up', 'Given basically everything we know about him, from his luxury expedition to Antarctica to his friendship with RFK Jr., Diplo profiles as an AI bro. It turns out he is. A few weeks ago, Diplo discussed AI in the music industry on Daniel Wall’s Behind The Wall podcast. A clip from the interview has gone…', 'https://stereogum.com/2495756/diplo-says-creatives-need-to-use-ai-or-give-up/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Diplo.png', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 18:54:36', '2026-04-14 22:26:43.658', '2026-04-14 22:26:43.658', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yfzz0003xphp701vlo3s', 'Hear The Rolling Stones’ Secret New 7″ Single “Rough And Twisted”', 'hear-the-rolling-stones-secret-new-7-single-rough-and-twisted', 'The Rolling Stones are almost certainly the most famous currently-active rock ‘n’ roll band on the face of the planet, and all the surviving members are roughly one billion years old. They don’t need to hype up a new record by doing viral-marketing stunts, but they’re doing it anyway. The Stones released their Andrew Watt-produced… The post Hear The Rolling Stones’ Secret New 7″ Single “Rough And Twisted” appeared first on Stereogum.', 'https://stereogum.com/2495761/hear-the-rolling-stones-secret-new-7-single-rough-and-twisted/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Rolling-Stones.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 18:45:51', '2026-04-14 22:26:44.735', '2026-04-14 22:26:44.735', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ygdk0004xphpxfp7y0o1', 'Okkervil River’s Will Sheff Announces New Album Extra Mile: Hear “Funny Feeling”', 'okkervil-river-s-will-sheff-announces-new-album-extra-mile-hear-funny-feeling', 'For more than a quarter century, Will Sheff has been the frontman of the ultra-literate indie rock band Okkervil River. But Okkervil River haven’t been active for years. In 2022, Sheff released is first-ever solo album Nothing Special, and we ran a whole feature about it. Right now, Sheff is out on tour as the… The post Okkervil River’s Will Sheff Announces New Album <em>Extra Mile</em>: Hear “Funny Feeling” appeared first on Stereogum.', 'https://stereogum.com/2495754/okkervil-rivers-will-sheff-announces-new-album-extra-mile-hear-funny-feeling/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Will-Sheff-Extra-Mile.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 18:24:44', '2026-04-14 22:26:45.224', '2026-04-14 22:26:45.224', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ygya0005xphp8xmktg95', 'J. Cole’s Chinese Basketball Era Ends After Eight Minutes Due To Visa Issues', 'j-cole-s-chinese-basketball-era-ends-after-eight-minutes-due-to-visa-issues', 'J. Cole has a sort of eccentric tradition. Whenever he releases an album, he likes to sign to a professional basketball team in a foreign country and really, really embarrass himself. In 2021, at the same time as he released his LP The Off-Season, Cole played three games for the Africa Basketball League’s Rwanda Patriots,…', 'https://stereogum.com/2495750/j-coles-chinese-basketball-era-ends-after-eight-minutes-due-to-visa-issues/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/J-Cole.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 17:56:03', '2026-04-14 22:26:45.97', '2026-04-14 22:26:45.97', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yhb80006xphpwzgjfocb', 'Theatre – “The Fall”', 'theatre-the-fall', 'The name is a stumbling block. I’ll admit that up front. It’s a stumbling block for me, anyway. Maybe you don’t have that problem. Maybe you’re like, “Oh, Theatre, what a perfectly normal and acceptable name for a band. What’s that? They actually stylize it THEATRE? That’s fine! I will honor that decision whenever I… The post Theatre – “The Fall” appeared first on Stereogum.', 'https://stereogum.com/2495738/theatre-the-fall/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Theatre.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 16:56:00', '2026-04-14 22:26:46.436', '2026-04-14 22:26:46.436', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yhno0007xphpbhaj7he0', 'Eli Edwards (Enumclaw) & Xay Young Announce Debut Casi Album: Hear “JUMPER”', 'eli-edwards-enumclaw-xay-young-announce-debut-casi-album-hear-jumper', 'The new duo Casi brings together Eli Edwards from Band To Watch alums Enumclaw with his childhood friend Xay Young. Edwards moved away from their Tacoma-area hometown in 2024 to relocate to LA with Enumclaw, but on return trips back home, he’s been working with Young on music that represents a big shift from Enumclaw’s… The post Eli Edwards (Enumclaw) & Xay Young Announce Debut Casi Album: Hear “JUMPER” appeared first on Stereogum.', 'https://stereogum.com/2495737/eli-edwards-enumclaw-xay-young-announce-debut-casi-album-hear-jumper/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-2026-04-14T123717.040.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 16:44:50', '2026-04-14 22:26:46.884', '2026-04-14 22:26:46.884', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yidc0008xphpf8u5ll91', 'Clannad Singer Moya Brennan Dead At 73', 'clannad-singer-moya-brennan-dead-at-73', 'Moya Brennan, singer and harpist for the new age Celtic folk group Clannad, has passed away. A social media statement from Brennan''s family says that she died at home in Donegal on Monday night, surrounded by family. According to The Guardian, Brennan had been living with pulmonary fibrosis in recent years. She was 73. The post Clannad Singer Moya Brennan Dead At 73 appeared first on Stereogum.', 'https://stereogum.com/2495731/clannad-singer-moya-brennan-dead-at-73/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Clannad.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 16:23:51', '2026-04-14 22:26:47.808', '2026-04-14 22:26:47.808', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yijt0009xphp571ht805', 'Tori Amos – “Gasoline Girls”', 'tori-amos-gasoline-girls', 'Tori Amos, a singer-songwriter with a lot of incredible music in her catalog, is busy right now. She’s currently on tour in the UK, and she recently covered Bob Dylan with the BBC Concert Orchestra and played her 2005 song “Witness” for only the second time ever at her tour opener. Amos’ new album In… The post Tori Amos – “Gasoline Girls” appeared first on Stereogum.', 'https://stereogum.com/2495728/tori-amos-gasoline-girls/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Tori-Amos.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 15:38:12', '2026-04-14 22:26:48.041', '2026-04-14 22:26:48.041', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yjla000axphpyi8or2gg', 'Genghis Tron Announce New Album Signal Fire: Hear “I Am All”', 'genghis-tron-announce-new-album-signal-fire-hear-i-am-all', 'It’s been five years since Genghis Tron’s Dream Weapon, which was their first album in 13 years. Luckily, this time they’re not making fans wait as long for a followup. Today the experimental metal band is announcing Signal Fire, arriving in June. The explosive, groovy “I Am All” serves as the lead single. “‘Signal Fire’… The post Genghis Tron Announce New Album <em>Signal Fire</em>: Hear “I Am All” appeared first on Stereogum.', 'https://stereogum.com/2495676/genghis-tron-announce-new-album-signal-fire-hear-i-am-all/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-81-1.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 15:26:50', '2026-04-14 22:26:49.39', '2026-04-14 22:26:49.39', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yjz0000bxphpw1xjwnnj', 'The Laughing Chimes Announce New Album Behind Your Blue Fields: Hear Two Songs', 'the-laughing-chimes-announce-new-album-behind-your-blue-fields-hear-two-songs', 'Today I’m headed back to Athens, Ohio, the pastoral southeastern Ohio college town where I spent my undergrad years, for the Ohio University Music Industry Summit. (Dev Hynes will be there!) In a beautiful coincidence, dreamy, jangly Athens post-punks the Laughing Chimes have announced their new album today too. Behind Your Blue Fields, out in… The post The Laughing Chimes Announce New Album <em>Behind Your Blue Fields</em>: Hear Two Songs appeared first on Stereogum.', 'https://stereogum.com/2495719/the-laughing-chimes-announce-new-album-behind-your-blue-fields-hear-two-songs/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/a1874628783_10.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 15:26:22', '2026-04-14 22:26:49.884', '2026-04-14 22:26:49.884', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ykep000cxphpciz30r56', 'Snarls Announce New EP In Heaven There’s Rainbows: Hear “No Lock, No Prayer”', 'snarls-announce-new-ep-in-heaven-there-s-rainbows-hear-no-lock-no-prayer', 'The sharp, efficient Columbus alt-rockers Snarls were a Stereogum Band To Watch in 2020, and they released their Chris Walla-produced album With Love in 2024. Snarls recently became a quartet with the addition of drummer Mike Taddeo, and now they’re announcing a new EP that’ll drop in a couple of months. Snarls recorded their new… The post Snarls Announce New EP <em>In Heaven There’s Rainbows</em>: Hear “No Lock, No Prayer” appeared first on Stereogum.', 'https://stereogum.com/2495717/snarls-announce-new-ep-in-heaven-theres-rainbows-hear-no-lock-no-prayer/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Snarls-In-Heaven-Theres-Rainbows.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 14:57:37', '2026-04-14 22:26:50.449', '2026-04-14 22:26:50.449', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yl71000dxphpku3da96p', 'Terra Twin Announce New EP Scumbag: Hear “Parking Lot”', 'terra-twin-announce-new-ep-scumbag-hear-parking-lot', 'The British actor Maxim Baldry has been on TV shows like Hollyoaks and Years And Years, and he’s currently in the cast of Amazon’s Lord Of The Rings series. On top of that, Baldry is the frontman of a London-based indie band called Terra Twin, who will soon head out on a European tour with… The post Terra Twin Announce New EP <em>Scumbag</em>: Hear “Parking Lot” appeared first on Stereogum.', 'https://stereogum.com/2495711/terra-twin-announce-new-ep-scumbag-hear-parking-lot/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Terra-Twin-Parking-Lot.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 14:31:43', '2026-04-14 22:26:51.469', '2026-04-14 22:26:51.469', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yllj000exphp4whnypaf', 'Waxahatchee Covers “Choosin’ Texas,” Announces Pregnancy At Tour Kickoff', 'waxahatchee-covers-choosin-texas-announces-pregnancy-at-tour-kickoff', 'Waxahatchee and MJ Lenderman kicked off their co-headlining acoustic tour Monday in Atlanta. It was an eventful night at Atlanta Symphony Hall, including a noteworthy cover and some exciting news from Katie Crutchfield. As one commenter on Reddit points out, Crutchfield introduced the night’s final song like so: “This is a song about having a… The post Waxahatchee Covers “Choosin’ Texas,” Announces Pregnancy At Tour Kickoff appeared first on Stereogum.', 'https://stereogum.com/2495668/waxahatchee-covers-choosin-texas-announces-pregnancy-at-tour-kickoff/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Waxahatchee-Press-Photo-by-Allison-Crutchfield.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 14:25:46', '2026-04-14 22:26:51.991', '2026-04-14 22:26:51.991', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ymn9000fxphp9xg5jvon', 'Joyful Noise Office Plants Release Debut Single With Deerhoof', 'joyful-noise-office-plants-release-debut-single-with-deerhoof', '“Do plants have consciousness? Is it possible to find a musical frequency in the biological rhythms of the organic world? Can creative authorship exist beyond the human form?” These are questions posed by the new project from Joyful Noise Recordings. The Sound Sanctuary is a “multi-species plant ensemble” housed in the label’s office, consisting of… The post Joyful Noise Office Plants Release Debut Single With Deerhoof appeared first on Stereogum.', 'https://stereogum.com/2495697/joyful-noise-office-plants-release-debut-single-with-deerhoof/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/JNR500-1-Deerhoof-Cover-Art-Final-copy.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 14:10:13', '2026-04-14 22:26:53.349', '2026-04-14 22:26:53.349', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ynff000gxphpgu38i4qk', 'G. Love Loses All His Retirement Savings In Crypto Scam', 'g-love-loses-all-his-retirement-savings-in-crypto-scam', 'The world of cryptocurrency is full of scammers, and the laid-back Philadelphia blues-rocker G. Love recently learned all about it the hard way. On Saturday, the G. Love & Special Sauce frontman, whose real name is Garrett Dutton, tweeted that he lost his "retirement fund in a hack/Scam." The post G. Love Loses All His Retirement Savings In Crypto Scam appeared first on Stereogum.', 'https://stereogum.com/2495703/g-love-loses-all-his-retirement-savings-in-crypto-scam/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/G-Love.png', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 14:07:39', '2026-04-14 22:26:54.363', '2026-04-14 22:26:54.363', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yo6y000hxphp1norf2ge', 'Hayley Williams & Jeff Tweedy Cover Unknown Mortal Orchestra On Colbert', 'hayley-williams-jeff-tweedy-cover-unknown-mortal-orchestra-on-colbert', 'Hayley Williams is in the thick of her first solo tour, and she just wrapped up three nights at New York City''s Hammerstein Ballroom, during which she brought out surprise guest Jason Isbell for a rendition of his song "Cover Me Up." Last night on The Late Show With Stephen Colbert, she and her backing band teamed up with another somewhat unlikely collaborator but a Colbert regular, Jeff Tweedy. Together, the respective Paramore and Wilco frontpeople did a cover of...', 'https://stereogum.com/2495696/hayley-williams-jeff-tweedy-cover-unknown-mortal-orchestra-on-colbert/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Williams-Tweedy.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 13:58:13', '2026-04-14 22:26:55.354', '2026-04-14 22:26:55.354', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yoiz000ixphp76kfne60', 'Nation Of Language – “Tougher Than The Rest” (Bruce Springsteen Cover)', 'nation-of-language-tougher-than-the-rest-bruce-springsteen-cover', 'New Bruce Springsteen covers are materializing like crazy this week, and not just the requisite “I’m On Fire” covers either. First came news of a Nicholas Krgovich’s Boss Tape and access to its opening track, “Gave It A Name.” Now we get a great one from Nation Of Language. The Sub Pop synth-pop trio has… The post Nation Of Language – “Tougher Than The Rest” (Bruce Springsteen Cover) appeared first on Stereogum.', 'https://stereogum.com/2495700/nation-of-language-tougher-than-the-rest-bruce-springsteen-cover/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/a3489309344_10.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 13:39:04', '2026-04-14 22:26:55.787', '2026-04-14 22:26:55.787', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yovg000jxphpl336bhhw', 'Liam Gallagher Reacts To Oasis’ Rock & Roll Hall Of Fame Induction News', 'liam-gallagher-reacts-to-oasis-rock-roll-hall-of-fame-induction-news', 'Despite Liam Gallagher''s best efforts, Oasis are going into the Rock And Roll Hall Of Fame. Last night, Ryan Seacrest and Lionel Richie announced this year''s class of Hall Of Fame inductees on American Idol. Oasis, on their third nomination, are among that number. In one of his extremely entertaining Twitter moments in 2024, first-time nominee Liam Gallagher expressed some reservations about the idea of the Hall Of Fame. Specifically, he wrote, "Fuck the Rock n Roll hall of fame...', 'https://stereogum.com/2495691/liam-gallagher-reacts-to-oasis-rock-roll-hall-of-fame-induction-news/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Liam-Gallagher.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 11:51:54', '2026-04-14 22:26:56.236', '2026-04-14 22:26:56.236', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yp97000kxphpmeuz4lwq', 'Rock & Roll Hall Of Fame 2026 Inductees Include Oasis, Iron Maiden, Phil Collins, & Joy Division/New Order', 'rock-roll-hall-of-fame-2026-inductees-include-oasis-iron-maiden-phil-collins-joy-division-new-order', 'We have a new set of acts heading into the Rock And Roll Hall Of Fame. Hall Of Famer Lionel Richie and Ryan Seacrest made the announcement during tonight''s HOF-themed American Idol episode. The 2026 class of Hall Of Fame inductees includes eight acts — or nine, depending on how you''re counting: Oasis, Iron Maiden, Phil Collins, the Wu-Tang Clan, Sade, Luther Vandross, Billy Idol, and the combination of Joy Division and New Order. The post Rock & Roll Hall...', 'https://stereogum.com/2495591/rock-roll-hall-of-fame-2026-inductees-include-oasis-iron-maiden-phil-collins-joy-division-new-order/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Oasis.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-14 01:15:55', '2026-04-14 22:26:56.731', '2026-04-14 22:26:56.731', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ypfx000lxphpets6tmt6', 'Nicholas Krgovich Announces Bruce Springsteen Covers Album Boss Tape: Hear “Gave It A Name”', 'nicholas-krgovich-announces-bruce-springsteen-covers-album-boss-tape-hear-gave-it-a-name', 'Nicholas Krgovich’s last solo album was 2023’s Ducks, but the following year he revived his long-dormant band P:ano for a new record called ba ba ba. Now he’s back to announce a Bruce Springsteen covers album titled Boss Tape, and his rendition of the 1998 track “Gave It A Name” is out today. “On November… The post Nicholas Krgovich Announces Bruce Springsteen Covers Album <em>Boss Tape</em>: Hear “Gave It A Name” appeared first on Stereogum.', 'https://stereogum.com/2495663/nicholas-krgovich-announces-bruce-springsteen-covers-album-boss-tape-hear-gave-it-a-name/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/a1517779719_10.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 23:07:41', '2026-04-14 22:26:56.973', '2026-04-14 22:26:56.973', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ypsh000mxphpydj3zcl8', 'Jorginho Finally Concedes Chappell Roan Did Not Make His Daughter Cry', 'jorginho-finally-concedes-chappell-roan-did-not-make-his-daughter-cry', 'Last month during Lollapalooza weekend in Brazil, Chappell Roan was under fire after Brazilian-Italian football star Jorginho accused the young pop sensation of making his daughter cry. He claimed that she sent her security guard to scold his daughter after she walked past Roan''s table during breakfast at a hotel. Roan said that the security guard was not a part of her team, and that was later verified. Now, Jorginho shared a statement saying he "regrets the impact" that his...', 'https://stereogum.com/2495659/jorginho-finally-concedes-chappell-roan-did-not-make-his-daughter-cry/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/chappell-roan-1.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 22:33:46', '2026-04-14 22:26:57.425', '2026-04-14 22:26:57.425', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ypz1000nxphp49kwneuz', 'Katy Perry Responds To Ruby Rose’s Sexual Assault Allegation', 'katy-perry-responds-to-ruby-rose-s-sexual-assault-allegation', 'Katy Perry spent this past weekend traipsing around Coachella and spending time with two Canadian Justins: Her boyfriend and former prime minister Trudeau, and Saturday night headliner Bieber. For a portion of Bieber''s set, he pulled out a laptop and started pulling up his old music videos on YouTube: "Thank God he has Premium, I don''t wanna see no ads," Perry remarked in a clip that''s since gone somewhat viral. The post Katy Perry Responds To Ruby Rose’s Sexual Assault...', 'https://stereogum.com/2495635/katy-perry-responds-to-ruby-roses-sexual-assault-allegation/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Katy-Perry.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 19:20:04', '2026-04-14 22:26:57.661', '2026-04-14 22:26:57.661', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6z1u4001bxphp73utohxz', 'The Strokes announce first Dublin show in 20 years', 'the-strokes-announce-first-dublin-show-in-20-years', 'The Strokes will play their first Dublin show in 20 years as part of their upcoming world tour.', 'https://www.rte.ie/entertainment/2026/0413/1567991-the-strokes-announce-first-dublin-show-in-20-years/', 'https://www.rte.ie/images/00243375-1600.jpg', false, false, NULL, 'cmns3qc5u0000idhpe8f9i7uq', '2026-04-13 14:42:32', '2026-04-14 22:27:13.036', '2026-04-14 22:27:13.036', false, 'via RTE Music', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yqos000oxphp0j5poxab', 'Paycheque Announce Self-Titled Debut Album: Hear “Generic Actress”', 'paycheque-announce-self-titled-debut-album-hear-generic-actress', 'LA-based duo Paycheque brings together Alison Goldfarb (Geranium) and Jackson MacIntosh of TOPS and Drugdealer. Their self-titled debut album is dropping in June, and its charming lead single is out now. “Generic Actress” has some of that intentionally chintzy retro special sauce you’d expect from an artist with MacIntosh’s associations, and with some nice guy-girl… The post Paycheque Announce Self-Titled Debut Album: Hear “Generic Actress” appeared first on Stereogum.', 'https://stereogum.com/2495643/paycheque-announce-self-titled-debut-album-hear-generic-actress/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-2026-04-13T144544.452.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 18:53:53', '2026-04-14 22:26:58.588', '2026-04-14 22:26:58.588', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yrbl000pxphpekt5jqhj', 'DJ Seinfeld – “Everything U”', 'dj-seinfeld-everything-u', 'Last month DJ Seinfeld announced his new album If This Is It, which is not a lo-fi house Strokes covers record but should be. The vocals on today’s new single “Everything U” are not in the Casablancosphere, but they do remind me of a distinctive singer by the name of Abel Tesfaye. Even when he… The post DJ Seinfeld – “Everything U” appeared first on Stereogum.', 'https://stereogum.com/2495639/dj-seinfeld-everything-u/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-2026-04-13T143957.975.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 18:41:14', '2026-04-14 22:26:59.409', '2026-04-14 22:26:59.409', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yro2000qxphppihtwc1z', 'Lindsey Buckingham’s Alleged Stalker Arrested In Indiana', 'lindsey-buckingham-s-alleged-stalker-arrested-in-indiana', 'Lindsey Buckingham was attacked by a woman on his way into an appointment in Santa Monica two weeks ago. Buckingham, the 76-year-old former Fleetwood Mac guitarist, reportedly was familiar with the woman from previous altercations. After dousing Buckingham with an unknown substance, she fled the scene, but now she''s been arrested thousands of miles away. The post Lindsey Buckingham’s Alleged Stalker Arrested In Indiana appeared first on Stereogum.', 'https://stereogum.com/2495633/lindsey-buckinghams-alleged-stalker-arrested-in-indiana/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Michelle-Dick.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 18:01:50', '2026-04-14 22:26:59.858', '2026-04-14 22:26:59.858', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ys19000rxphpoifd11s3', 'Parts & Labor Announce First New Album In 15 Years Set Of All Sets, Reunion Tour', 'parts-labor-announce-first-new-album-in-15-years-set-of-all-sets-reunion-tour', 'It’s been over 15 years since we last heard new music from Parts & Labor, the New York City noise rockers who played their farewell show in 2012. But they’ll be making up for that lost time soon: Set Of All Sets, a double album and their first LP since 2011’s Constant Future, is out… The post Parts & Labor Announce First New Album In 15 Years <em>Set Of All Sets</em>, Reunion Tour appeared first on Stereogum.', 'https://stereogum.com/2495615/parts-labor-announce-first-new-album-in-15-years-set-of-all-sets-reunion-tour/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Parts-And-Labor-set-of-all-sets.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 16:06:30', '2026-04-14 22:27:00.333', '2026-04-14 22:27:00.333', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yvb1000sxphpgvg8e0za', 'Labrinth Drops “SHUT YOUR DAMN 95.7892” During Euphoria Premiere', 'labrinth-drops-shut-your-damn-95-7892-during-euphoria-premiere', 'The UK musician Labrinth was responsible for the sleek, moody music in the first two seasons of HBO’s ultra-tawdry series Euphoria. Now, Euphoria is back for its long-awaited third season, and Labrinth isn’t part of it. Yesterday, Labrinth released a pissed-off single, and the timing is auspicious. Back in 2025, Labrinth announced that he was… The post Labrinth Drops “SHUT YOUR DAMN 95.7892” During <em>Euphoria</em> Premiere appeared first on Stereogum.', 'https://stereogum.com/2495621/labrinth-drops-shut-your-damn-95-7892-during-euphoria-premiere/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Labrinth.jpeg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 15:17:43', '2026-04-14 22:27:04.573', '2026-04-14 22:27:04.573', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yvp1000txphpxdzxwzs0', 'Laufey Unveils “Madwoman” Video, Erewhon Smoothie, Fornite Skin, Electric Lexus Honoring Miles Davis For Amazon', 'laufey-unveils-madwoman-video-erewhon-smoothie-fornite-skin-electric-lexus-honoring-miles-davis-for-', 'Here at Stereogum, we haven''t had too much to say about the Icelandic jazz-pop singer Laufey, but she is a very big deal now. She''s got five platinum singles, and her 2024 album A Matter Of Time won the Grammy for Best Traditional Pop Vocal Album. At the Olympics, gold medal-winning figure skater Alysa Liu skated to Laufey''s song "Promise." On Sunday, Laufey played one of the main stages at Coachella. Now, Laufey''s name is turning up in all sorts...', 'https://stereogum.com/2495608/laufey-unveils-madwoman-video-erewhon-smoothie-electric-lexus-honoring-miles-davis-for-amazon/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Laufey.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 14:46:59', '2026-04-14 22:27:05.077', '2026-04-14 22:27:05.077', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yw3x000uxphp1octueij', 'Truck Violence Announce New Album The Weathervane Is My Body: Hear “New Jesus”', 'truck-violence-announce-new-album-the-weathervane-is-my-body-hear-new-jesus', 'Two decades ago there used to be this amazing band in Columbus called El Jesus de Magico. One of their best songs was called “New Moses.” The first time I saw them perform it in 2005, I just about lost my mind. (That was around the same time I was getting into their peers Times… The post Truck Violence Announce New Album <em>The Weathervane Is My Body</em>: Hear “New Jesus” appeared first on Stereogum.', 'https://stereogum.com/2495614/truck-violence-announce-new-album-the-weathervane-is-my-body-hear-new-jesus/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-2026-04-13T102006.494.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 14:34:11', '2026-04-14 22:27:05.613', '2026-04-14 22:27:05.613', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ywk6000vxphpc19woyue', 'Hayley Williams Covers “Cover Me Up” With Jason Isbell In NYC', 'hayley-williams-covers-cover-me-up-with-jason-isbell-in-nyc', '"Cover Me Up" is probably one of Jason Isbell''s best-known songs, and that''s at least partially due to the fact that Morgan Wallen included a cover of the 2013 song on his 2021 album Dangerous: The Double Album. In the weeks following its release, though, Wallen was filmed drunkenly yelling a racial slur, after which Isbell famously pledged to donate his royalties from Wallen''s "Cover Me Up" cover to the NAACP. Wallen''s controversy certainly didn''t prevent him from becoming one...', 'https://stereogum.com/2495597/hayley-williams-covers-cover-me-up-with-jason-isbell-in-nyc/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/Hayley-Williams-Jason-Isbell.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 14:12:36', '2026-04-14 22:27:06.198', '2026-04-14 22:27:06.198', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6z1yx001cxphpd1pijwwh', 'Behind the music - Paul Archer', 'behind-the-music-paul-archer', 'Northern Irish singer Paul Archer has released the music video for his song No Fear from his debut solo album, Art. We asked him the BIG questions . . .', 'https://www.rte.ie/entertainment/2026/0413/1565946-behind-the-music-paul-archer/', 'https://www.rte.ie/images/002431ef-1600.jpg', false, false, NULL, 'cmns3qc5u0000idhpe8f9i7uq', '2026-04-13 06:00:00', '2026-04-14 22:27:13.209', '2026-04-14 22:27:13.209', false, 'via RTE Music', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6ywwl000wxphpto8jd82r', 'The Strokes Announce 2026 Tour Dates With Thundercat, Hamilton Leithauser, & More', 'the-strokes-announce-2026-tour-dates-with-thundercat-hamilton-leithauser-more', 'The Strokes are entering into full-on blitz mode for 2026. They''re playing a bunch of festivals, starting with Coachella, and releasing Reality Awaits, their first new album in six years. Today they''ve filled in the gaps between all those fests with dozens more tour dates across North America and Europe, plus a two-night stop-off in Japan. The post The Strokes Announce 2026 Tour Dates With Thundercat, Hamilton Leithauser, & More appeared first on Stereogum.', 'https://stereogum.com/2495603/the-strokes-announce-2026-tour-dates-with-thundercat-hamilton-leithauser-more/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-2026-04-13T095334.262.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 14:08:00', '2026-04-14 22:27:06.645', '2026-04-14 22:27:06.645', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yx99000xxphpdxjicjh6', 'Morrissey Calls Johnny Marr’s Rough Trade Narrative “Deliberately Untrue”', 'morrissey-calls-johnny-marr-s-rough-trade-narrative-deliberately-untrue', 'You''re never going to believe this, but Morrissey is once again publicly upset with his former Smiths bandmate Johnny Marr. Those two have been at odds with one another for decades, and Morrissey generally isn''t shy about popping off on Marr online. It happened again yesterday. The post Morrissey Calls Johnny Marr’s Rough Trade Narrative “Deliberately Untrue” appeared first on Stereogum.', 'https://stereogum.com/2495596/morrissey-calls-johnny-marrs-rough-trade-narrative-deliberately-untrue/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/The-Smiths.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 13:55:30', '2026-04-14 22:27:07.101', '2026-04-14 22:27:07.101', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6yxsx000yxphptfio04z2', 'RFK Jr. Allies M.I.A. & Diplo Reunite For “Paper Planes” At Coachella', 'rfk-jr-allies-m-i-a-diplo-reunite-for-paper-planes-at-coachella', 'Diplo and M.I.A. will probably always be best known for the legendary music they made together in the mid-2000s. Piracy Funds Terrorism, Arular, Kala — what an insane run. It would be great if we could just leave them in that golden moment, but as time has passed, the two have become infamous. 
INSERT INTO "NewsArticle" VALUES ('cmnz6yxth000zxphplcrbbebh', 'The Number Ones: The Weeknd & Ariana Grande’s “Save Your Tears (Remix)”', 'the-number-ones-the-weeknd-ariana-grande-s-save-your-tears-remix', 'In The Number Ones, I’m reviewing every single #1 single in the history of the Billboard Hot 100, starting with the chart’s beginning, in 1958, and working my way up into the present. The column is now biweekly, alternating with The Alternative Number Ones on Mondays. Book Bonus Beat: The Number Ones: Twenty Chart-Topping Hits…', 'https://stereogum.com/2494430/the-number-ones-the-weeknd-ariana-grandes-save-your-tears-remix/columns/the-number-ones/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/The-Weeknd-Save-Your-Tears.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-13 12:39:08', '2026-04-14 22:27:07.829', '2026-04-14 22:27:07.829', false, 'Stereogum', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6z01i0010xphp4vlx9uwx', 'Obituary - Moya Brennan: the first lady of Celtic music', 'obituary-moya-brennan-the-first-lady-of-celtic-music', 'It was like nothing your average Top of The Pops fan had heard before.', 'https://www.rte.ie/entertainment/2026/0414/1568219-obituary-moya-brennan-the-first-lady-of-celtic-music/', 'https://www.rte.ie/images/001d39a2-1600.jpg', false, false, NULL, 'cmns3qc5u0000idhpe8f9i7uq', '2026-04-14 15:32:50', '2026-04-14 22:27:10.71', '2026-04-14 22:27:10.71', false, 'via RTE Music', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6z02c0011xphpig2vx9va', 'President leads moving tributes to Moya Brennan', 'president-leads-moving-tributes-to-moya-brennan', 'President Catherine Connolly has led tributes to Moya Brennan after the Clannad star died aged 73.', 'https://www.rte.ie/entertainment/2026/0414/1565945-moya-brennan-hailed-as-one-of-irelands-jewels/', 'https://www.rte.ie/images/00243703-1600.jpg', false, false, NULL, 'cmns3qc5u0000idhpe8f9i7uq', '2026-04-13 23:00:00', '2026-04-14 22:27:10.741', '2026-04-14 22:27:10.741', false, 'via RTE Music', NULL);
INSERT INTO "NewsArticle" VALUES ('cmnz6z0360012xphpmrbh3261', 'Irish musician Moya Brennan dies aged 73', 'irish-musician-moya-brennan-dies-aged-73', 'Moya Brennan, best known as the lead singer of the Grammy and BAFTA-winning group Clannad, died peacefully yesterday, surrounded by her family, at the age of 73.', 'https://www.rte.ie/entertainment/2026/0414/1568068-moya-brennan-clannad/', 'https://www.rte.ie/images/002436e4-1600.jpg', false, false, NULL, 'cmns3qc5u0000idhpe8f9i7uq', '2026-04-14 05:01:20', '2026-04-14 22:27:10.77', '2026-04-14 22:27:10.77', false, 'via RTE Music', NULL);
